-- Schema for Domain: finance | Business: Sports Entertainment | Version: v1_mvm
-- Generated on: 2026-05-09 04:52:10

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`finance` COMMENT 'Corporate financial domain owning general ledger, cost centers, budgets, EBITDA reporting, ARR tracking, financial planning and analysis (FP&A), and SOX-compliant financial controls via SAP S/4HANA FI/CO. Manages chart of accounts, revenue recognition, expense allocation, intercompany settlements, and SEC financial reporting for publicly traded entities. SSOT for all enterprise financial master data.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`gl_account` (
    `gl_account_id` BIGINT COMMENT 'Unique surrogate identifier for the GL account master record in the Databricks Silver Layer. Primary key for all downstream joins and lineage tracking. Role: MASTER_RESOURCE.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: GL accounts in SAP FI are defined within a specific company codes chart of accounts. The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.',
    `account_changed_by` STRING COMMENT 'SAP user ID of the person who last modified this GL account master record (SKA1.AEDTM user). Required for SOX audit trail, segregation of duties compliance, and internal audit reviews. Supports detection of unauthorized changes to chart of accounts master data.',
    `account_changed_date` DATE COMMENT 'Date on which this GL account master record was last modified (SKA1.LAEDA). Used for change management tracking, SOX compliance, and data lineage in the Databricks Silver Layer. Triggers downstream reprocessing of dependent financial reporting datasets when account attributes change.',
    `account_created_by` STRING COMMENT 'SAP user ID of the person who created this GL account master record (SKA1.ERNAM). Required for SOX audit trail and segregation of duties (SoD) compliance. Enables identification of unauthorized account creation and supports internal audit reviews of chart of accounts governance.',
    `account_created_date` DATE COMMENT 'Date on which this GL account master record was first created in the chart of accounts (SKA1.ERDAT). Used for audit trail, SOX compliance documentation, and chart of accounts change management reporting. Supports identification of accounts created outside of standard change control processes.',
    `account_group_code` STRING COMMENT 'SAP account group (SKA1.KTOKS) that controls the number range and field selection for the GL account. Groups accounts by business function, e.g., revenue accounts, expense accounts, balance sheet accounts. Determines which fields are required, optional, or suppressed during account maintenance.. Valid values are `^[A-Z0-9]{4}$`',
    `account_long_name` STRING COMMENT 'Extended descriptive name of the GL account (SKAT.TXT50) providing full business context. Used in detailed financial disclosures, audit documentation, and SEC reporting narratives.',
    `account_name` STRING COMMENT 'Short descriptive name of the GL account as maintained in SAP S/4HANA (SKAT.TXT20). Used on financial reports, trial balances, and chart of accounts listings. Examples: Ticket Revenue, Broadcast Rights Income, Player Salary Expense, Naming Rights Deferred Revenue.',
    `account_number` STRING COMMENT 'The externally-known, human-readable GL account number as defined in the SAP S/4HANA chart of accounts (SKA1.SAKNR). Uniquely identifies the posting target within a chart of accounts. Used on all journal entries, financial statements, and cost element assignments.. Valid values are `^[0-9]{6,10}$`',
    `account_status` STRING COMMENT 'Current lifecycle status of the GL account master record. active accounts accept postings; blocked accounts are temporarily prevented from receiving new journal entries; marked_for_deletion accounts are pending archival after period-end close. Controls posting eligibility across all Sports Entertainment legal entities.. Valid values are `active|blocked|marked_for_deletion`',
    `account_type` STRING COMMENT 'Fundamental financial classification of the GL account indicating its role in the financial statements (SKA1.KTOKS mapped to account type). asset and liability and equity are balance sheet accounts; revenue and expense are profit and loss (P&L) accounts. Drives financial statement line assignment and period-end closing behavior.. Valid values are `asset|liability|equity|revenue|expense`',
    `alternative_account_number` STRING COMMENT 'Alternative account number used for country-specific or group reporting chart of accounts mapping (SKA1.ALTKT). Enables mapping between the operational chart of accounts and a group consolidation chart of accounts or statutory reporting chart of accounts for international league entities operating under different GAAP/IFRS frameworks.',
    `balance_sheet_account` BOOLEAN COMMENT 'Indicates whether this GL account is a balance sheet account (True) or a profit and loss (P&L) income statement account (False) (SKA1.XBILK). Balance sheet accounts carry forward balances at year-end; P&L accounts are closed to retained earnings. Fundamental for period-end close processing and financial statement preparation.',
    `chart_of_accounts_code` STRING COMMENT 'Four-character SAP chart of accounts key (SKA1.KTOPL) to which this GL account belongs. Sports Entertainment may maintain multiple charts of accounts for different legal entity frameworks (e.g., US GAAP vs IFRS for international leagues). Determines the account structure and financial statement mapping.. Valid values are `^[A-Z0-9]{4}$`',
    `commitment_management` BOOLEAN COMMENT 'Indicates whether commitment management (purchase order commitments and funds reservations) is active for this GL account. When True, purchase orders and contracts posted against this account create budget commitments visible in FP&A reporting. Relevant for player contract commitments, venue capital expenditure, and broadcast production cost commitments.',
    `controlling_area` STRING COMMENT 'Four-character SAP Controlling area code to which this GL accounts cost element is assigned (SKA1 CO integration). The controlling area defines the organizational unit within which cost and revenue accounting is performed. Enables cross-company-code cost allocation, internal order settlement, and EBITDA reporting across Sports Entertainments multi-entity structure.. Valid values are `^[A-Z0-9]{4}$`',
    `cost_center_required` BOOLEAN COMMENT 'Indicates whether a cost center assignment is mandatory when posting to this GL account. When True, all journal entries must include a valid cost center (e.g., venue operations cost center, broadcast production cost center, athlete management cost center). Enforces cost allocation discipline for EBITDA reporting and FP&A variance analysis.',
    `cost_element_category` STRING COMMENT 'Defines the cost element category in SAP Controlling (CO) module when this GL account is also a primary cost element (SKA1.KATYP). primary cost elements correspond directly to P&L GL accounts (e.g., player salary expense, venue operating cost, broadcast production cost); secondary cost elements are used for internal allocations and settlements between cost centers; none for balance sheet accounts not used in CO. Critical for EBITDA reporting and cost center allocation in FP&A.. Valid values are `primary|secondary|none`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the account currency in which balances are maintained (SKB1.WAERS). Sports Entertainment operates across global markets with revenues in USD, EUR, GBP, CAD, AUD, and other currencies. Accounts may be maintained in local currency, group currency (USD), or hard currency. Drives foreign currency revaluation and translation for consolidated SEC reporting.. Valid values are `^[A-Z]{3}$`',
    `deletion_flag` BOOLEAN COMMENT 'Indicates whether this GL account has been flagged for deletion from the chart of accounts (SKA1.XLOEV). Accounts flagged for deletion cannot receive new postings and are scheduled for archival after all dependent records are cleared. Supports chart of accounts rationalization and SOX control compliance.',
    `field_status_group` STRING COMMENT 'SAP field status group code assigned to the GL account that controls which fields are required, optional, or suppressed during document entry (SKB1.FSTAG). Ensures data completeness for postings — for example, cost center is required on expense accounts, profit center on revenue accounts, and business area on intercompany settlement accounts.. Valid values are `^[A-Z][0-9]{3}$`',
    `financial_statement_item` STRING COMMENT 'The financial statement version item code to which this GL account is assigned for external reporting (SKA1.BILKT). Maps the account to a specific line on the income statement, balance sheet, or cash flow statement as required for SEC 10-K/10-Q filings and EBITDA reporting.',
    `functional_area` STRING COMMENT 'Business functional area to which this GL account is assigned for segment and functional reporting (SKA1.FUNC_AREA). Enables profit and loss reporting by business function such as event operations, broadcast, athlete management, venue operations, merchandise, sponsorship, and corporate. Supports SEC segment reporting requirements under GAAP ASC 280.',
    `house_bank_account` BOOLEAN COMMENT 'Indicates whether this GL account is a house bank account used for cash management and bank reconciliation (SKB1.XINTB). When True, the account is linked to a physical bank account for automated bank statement processing, cash pooling, and treasury operations. Relevant for Sports Entertainments multi-entity cash management across leagues and venues.',
    `intercompany_account` BOOLEAN COMMENT 'Indicates whether this GL account is designated for intercompany transactions between Sports Entertainment legal entities (e.g., between the league holding company, individual team entities, broadcast subsidiaries, and venue operating companies). When True, intercompany partner must be specified on postings for automated elimination in consolidated financial statements. Required for SOX-compliant intercompany reconciliation.',
    `interest_calculation` BOOLEAN COMMENT 'Indicates whether automatic interest calculation is activated for this GL account (SKB1.XINTB for interest indicator). Relevant for intercompany loan accounts, deferred revenue accounts (naming rights, multi-year broadcast deals), and overdue receivable accounts where interest accrual is contractually required.',
    `line_item_display` BOOLEAN COMMENT 'Indicates whether individual line items are stored and displayable for this GL account (SKB1.XKRES). When True, each posting line is retained for drill-down reporting and audit trail purposes. Required for SOX-compliant audit trails on revenue accounts (ticket revenue, broadcast rights income, sponsorship fees) and significant expense accounts (player salaries, venue operating costs).',
    `open_item_management` BOOLEAN COMMENT 'Indicates whether open item management is activated for this GL account (SKB1.XOPVW). When True, individual line items remain open until explicitly cleared against an offsetting entry (e.g., deferred revenue accounts for naming rights, advance ticket deposits, broadcast rights prepayments). Enables aging analysis and outstanding item tracking for FP&A.',
    `planning_level` STRING COMMENT 'Planning level code that controls how this GL account participates in financial planning and budgeting processes in SAP CO and Workday Adaptive Planning integration. Determines the granularity at which budget vs. actual variance analysis is performed — account level, cost center level, or profit center level. Supports FP&A EBITDA budgeting and ARR tracking.',
    `posting_block` BOOLEAN COMMENT 'Flag indicating whether postings to this GL account are currently blocked at the chart of accounts level (SKA1.XSPEA). When True, no journal entries can be posted to this account regardless of company code settings. Used during account restructuring, period-end close, or SOX control enforcement.',
    `profit_center_required` BOOLEAN COMMENT 'Indicates whether a profit center assignment is mandatory when posting to this GL account. When True, all postings must include a valid profit center enabling segment-level profitability reporting (e.g., by league, by venue, by broadcast network). Supports SEC segment reporting under GAAP ASC 280 and internal EBITDA reporting by business unit.',
    `reconciliation_account_type` STRING COMMENT 'Indicates whether this GL account serves as a reconciliation account for a subledger and, if so, which subledger type (SKA1.MITKZ). customer reconciliation accounts aggregate accounts receivable subledger balances (e.g., fan ticket receivables, sponsor invoices); vendor for accounts payable (e.g., venue contractor payables); asset for fixed asset subledger (e.g., stadium infrastructure); none for non-reconciliation accounts. Direct postings to reconciliation accounts are blocked.. Valid values are `customer|vendor|asset|none`',
    `revenue_recognition_category` STRING COMMENT 'Classification of the revenue recognition pattern applicable to this GL account under GAAP ASC 606 / IFRS 15. point_in_time for single-event revenues (e.g., individual ticket sales, PPV events, merchandise sales); over_time for performance obligations satisfied over a period (e.g., season ticket packages, multi-year broadcast rights, naming rights); deferred for advance payments not yet earned (e.g., prepaid sponsorship fees, advance broadcast rights payments); not_applicable for non-revenue accounts. Critical for SEC revenue disclosure and audit compliance.. Valid values are `point_in_time|over_time|deferred|not_applicable`',
    `sort_key` STRING COMMENT 'Three-digit sort key code that determines the assignment field populated in the allocation field of line items posted to this account (SKB1.ZUAWA). Controls how line items are sorted and grouped in account displays and reports. Common sort keys include posting date, document number, and external document reference for reconciliation purposes.. Valid values are `^[0-9]{3}$`',
    `source_system_code` STRING COMMENT 'Identifier of the operational source system from which this GL account master record was extracted (e.g., SAP_S4HANA_PROD, SAP_S4HANA_EU). Supports multi-instance SAP landscapes where Sports Entertainment operates separate SAP systems for different regions or leagues. Enables data lineage tracking and conflict resolution in the Databricks Silver Layer.',
    `sports_revenue_stream` STRING COMMENT 'Sports Entertainment-specific revenue stream classification for this GL account, enabling industry-specific financial analytics and KPI reporting. Examples: ticket_revenue, broadcast_rights_income, naming_rights_revenue, sponsorship_fees, merchandise_licensing, ppv_revenue, concession_revenue, player_transfer_fee, nil_licensing_income, venue_rental. Used for EBITDA decomposition, ARR tracking, and league financial reporting. [ENUM-REF-CANDIDATE: ticket_revenue|broadcast_rights_income|naming_rights_revenue|sponsorship_fees|merchandise_licensing|ppv_revenue|concession_revenue|player_transfer_fee|nil_licensing_income|venue_rental — promote to reference product]',
    `tax_category` STRING COMMENT 'Tax category assigned to the GL account controlling tax code entry behavior during posting (SKB1.MWSKZ). Determines whether tax codes are required, optional, or not allowed on journal entries to this account. Relevant for VAT/GST on international broadcast rights, ticket sales tax, merchandise sales tax, and venue concession tax compliance.',
    `tax_relevant` BOOLEAN COMMENT 'Indicates whether this GL account is subject to tax reporting and requires a tax code on postings (SKB1.XMWNO negated). When True, postings must include a valid tax code for VAT, sales tax, or withholding tax compliance. Critical for international broadcast rights distribution, PPV revenue, and merchandise sales across jurisdictions.',
    `tolerance_group` STRING COMMENT 'Tolerance group code assigned to the GL account that defines acceptable variance thresholds for payment differences, rounding, and clearing (SKB1.ZUAWA tolerance reference). Controls automatic clearing of small differences on high-volume accounts such as ticket revenue clearing, merchandise POS settlement, and concession cash accounts. Supports SOX-compliant payment processing controls.',
    `valid_from_date` DATE COMMENT 'Date from which this GL account is valid and available for posting. Supports time-dependent account activation for new business lines (e.g., a new OTT streaming revenue account activated at the start of a new broadcast deal, or a new NIL licensing income account activated upon regulatory approval). Enables historical accuracy in financial reporting.',
    `valid_to_date` DATE COMMENT 'Date until which this GL account is valid for posting. Null indicates the account has no planned expiry. Used to retire accounts associated with discontinued business lines (e.g., a closed venue, an expired broadcast rights agreement, a divested team entity) while preserving historical posting data for audit and SEC reporting.',
    CONSTRAINT pk_gl_account PRIMARY KEY(`gl_account_id`)
) COMMENT 'General ledger account master record defining a specific financial classification node within the enterprise chart of accounts. Each GL account represents a unique posting target (e.g., ticket revenue, broadcast rights income, venue operating expense, player salary, naming rights deferred revenue). Stores account number, description, account type (P&L vs balance sheet), currency, tax category, reconciliation account flag, cost element category, account group, and posting block status. SSOT for all account classification, financial statement line mapping, and cost element definitions across all Sports Entertainment legal entities in SAP S/4HANA FI.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`cost_center` (
    `cost_center_id` BIGINT COMMENT 'Unique surrogate identifier for the cost center record in the Sports Entertainment lakehouse Silver layer. Primary key generated by the platform.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Cost centers in SAP CO belong to a specific company code (legal entity). The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.company_code_',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Cost centers are assigned to profit centers in SAP CO for segment reporting. The profit_center_code string field is a denormalized reference that should be replaced with a typed FK to profit_center.pr',
    `venue_id` BIGINT COMMENT 'Reference to the physical venue or facility primarily associated with this cost center, where applicable (e.g., a venue operations cost center linked to a specific arena). Enables venue-level cost analysis and facility management reporting.',
    `activity_type_code` STRING COMMENT 'Primary SAP CO activity type associated with this cost center, representing the unit of output or service provided (e.g., BROADCAST_HR for broadcast production hours, VENUE_DAY for venue operating days). Used for activity-based cost allocation and internal service pricing.. Valid values are `^[A-Z0-9_-]{1,16}$`',
    `allocation_method` STRING COMMENT 'Method used to allocate or settle costs from this cost center to other cost objects at period end: direct (direct activity allocation), assessment (using assessment cycles), distribution (using distribution cycles), activity_based (ABC costing), or statistical (for reporting only, no actual settlement).. Valid values are `direct|assessment|distribution|activity_based|statistical`',
    `budget_amount` DECIMAL(18,2) COMMENT 'Total approved annual budget allocated to this cost center for the current fiscal year, expressed in the cost centers primary currency. Sourced from Workday Adaptive Planning and loaded into SAP CO for variance reporting. Used in EBITDA forecasting and FP&A dashboards.',
    `business_domain` STRING COMMENT 'Sports Entertainment business domain that this cost center primarily supports. Enables cross-domain EBITDA analysis and cost attribution across the enterprise (e.g., venue for arena operations, broadcast for OTT/RSN production costs). [ENUM-REF-CANDIDATE: venue|broadcast|athlete|league|sponsorship|merchandise|ticketing|fan_engagement|content|finance|workforce|compliance|digital_platform — promote to reference product]',
    `business_unit` STRING COMMENT 'Sports Entertainment business unit or division that owns this cost center (e.g., NFL Operations, OTT Streaming, Venue Management, Athlete Performance). Used for segment-level EBITDA reporting and ARR tracking.',
    `controlling_area_code` STRING COMMENT 'SAP CO controlling area to which this cost center belongs. The controlling area defines the organizational unit within which cost accounting is performed and cross-company cost allocations are managed (e.g., SE01 for Sports Entertainment North America).. Valid values are `^[A-Z0-9]{1,4}$`',
    `cost_center_category` STRING COMMENT 'Single-character or two-character SAP CO cost center category code that controls which activity types and statistical key figures can be posted (e.g., A = general, B = production, F = financial). Determines default allocation rules and reporting groupings.. Valid values are `^[A-Z0-9]{1,2}$`',
    `cost_center_code` STRING COMMENT 'Alphanumeric code uniquely identifying the cost center within the controlling area, as defined in SAP CO. This is the externally-known business identifier used in journal entries, purchase orders, and budget allocations (e.g., VEN-OPS-001, BCAST-PROD-02).. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `cost_center_description` STRING COMMENT 'Free-text description of the cost centers business purpose, scope of operations, and cost accountability. Provides context for financial analysts, auditors, and FP&A teams beyond what the name and code convey (e.g., Responsible for all operational costs of the home venue including HVAC, BMS, security, and event-day staffing).',
    `cost_center_name` STRING COMMENT 'Full descriptive name of the cost center as maintained in SAP CO master data (e.g., Venue Operations — Staples Center, Broadcast Production — NFL Sunday Package). Used in financial reports, budget dashboards, and FP&A outputs.',
    `cost_center_status` STRING COMMENT 'Current lifecycle status of the cost center in SAP CO: active (accepting postings), inactive (temporarily suspended), locked (blocked for all postings), pending_activation (created but not yet effective), or archived (historical, no postings allowed). Drives period-end close controls and SOX compliance checks.. Valid values are `active|inactive|locked|pending_activation|archived`',
    `cost_center_type` STRING COMMENT 'SAP CO cost center category classifying the nature of cost incurrence: overhead (administrative/support), production (direct event/broadcast output), service (shared services), profit (revenue-generating unit tracked as cost center), or investment (capital project support). Drives allocation methodology and EBITDA reporting treatment.. Valid values are `overhead|production|service|profit|investment`',
    `cost_element_group` STRING COMMENT 'SAP CO cost element group defining the set of primary cost elements (GL accounts) that can be posted to this cost center. Controls which expense categories are tracked here (e.g., VENUE_OPEX for venue operating expenses, TALENT_COSTS for athlete/performer costs).. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary country where this cost center operates. Used for statutory reporting, VAT/tax jurisdiction assignment, and GDPR/CCPA data residency compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this cost center master record was first created in SAP CO. Used for audit trail, SOX compliance documentation, and data lineage tracking in the lakehouse Silver layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code representing the primary transaction currency for this cost center (e.g., USD, EUR, GBP). Drives currency translation in SAP FI/CO and multi-currency EBITDA consolidation.. Valid values are `^[A-Z]{3}$`',
    `department_code` STRING COMMENT 'Organizational department code associated with this cost center, aligned to the SAP SuccessFactors organizational hierarchy. Enables workforce cost attribution and headcount-to-cost analysis across Sports Entertainment business units.. Valid values are `^[A-Z0-9_-]{2,16}$`',
    `fiscal_year` STRING COMMENT 'Fiscal year to which the budget amount and planning data for this cost center applies (e.g., 2024, 2025). Aligns with the Sports Entertainment fiscal calendar defined in SAP FI company code settings.',
    `functional_area_code` STRING COMMENT 'SAP FI/CO functional area classifying the cost center by business function for cost-of-sales accounting and segment reporting (e.g., ADMIN, SALES, PROD, R&D). Required for SEC income statement presentation under US GAAP.. Valid values are `^[A-Z0-9_-]{1,16}$`',
    `geographic_region` STRING COMMENT 'Geographic region or market where this cost center primarily operates (e.g., North America, EMEA, APAC). Supports regional cost allocation, transfer pricing compliance, and multi-market EBITDA reporting.',
    `gl_account_group` STRING COMMENT 'SAP FI GL account group associated with this cost center, defining the range of general ledger accounts used for cost postings. Ensures chart-of-accounts alignment and supports automated financial statement mapping for SEC reporting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `hierarchy_level` STRING COMMENT 'Numeric level of this cost center within the standard cost center hierarchy (e.g., 1 = enterprise, 2 = division, 3 = department, 4 = operational unit). Used for rollup reporting in Workday Adaptive Planning and SAP CO standard hierarchy.',
    `intercompany_flag` BOOLEAN COMMENT 'Indicates whether this cost center participates in intercompany cost settlements between Sports Entertainment legal entities (True = intercompany). Triggers intercompany elimination entries in consolidated financial statements and SEC reporting.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent change to this cost center master record in SAP CO. Supports change detection for incremental lakehouse loads, SOX audit trails, and master data governance reviews.',
    `plan_lock` BOOLEAN COMMENT 'Indicates whether budget/plan postings to this cost center are currently blocked (True = locked). Prevents changes to approved budgets after the planning cycle is closed in Workday Adaptive Planning and SAP CO.',
    `posting_lock` BOOLEAN COMMENT 'Indicates whether actual cost postings to this cost center are currently blocked (True = locked, no postings allowed). Used during period-end close, organizational restructuring, or SOX audit freeze periods to prevent unauthorized cost entries.',
    `sap_changed_by` STRING COMMENT 'SAP user ID of the person who last modified this cost center master record. Required for SOX change management controls and audit trail. Stored as the SAP logon ID.. Valid values are `^[A-Z0-9_]{1,12}$`',
    `sap_created_by` STRING COMMENT 'SAP user ID of the person who created this cost center master record in SAP CO. Required for SOX segregation-of-duties controls and audit trail documentation. Stored as the SAP logon ID (not personal name).. Valid values are `^[A-Z0-9_]{1,12}$`',
    `segment_code` STRING COMMENT 'SEC/IFRS 8 reportable segment to which this cost center belongs for external financial disclosure (e.g., LIVE_EVENTS, MEDIA_RIGHTS, MERCHANDISE). Drives segment footnote disclosures in SEC Form 10-K and quarterly 10-Q filings.. Valid values are `^[A-Z0-9_-]{2,16}$`',
    `short_name` STRING COMMENT 'Abbreviated display name for the cost center used in condensed financial reports, dashboards, and SAP transaction screens where space is limited (max 20 characters per SAP CO standard).. Valid values are `^.{1,20}$`',
    `source_system` STRING COMMENT 'Operational system of record from which this cost center master record was sourced (e.g., SAP_S4HANA for records originating from SAP CO, WORKDAY for records originating from Workday Adaptive Planning, MANUAL for manually entered records). Supports data lineage and reconciliation.. Valid values are `SAP_S4HANA|WORKDAY|MANUAL`',
    `sox_relevant` BOOLEAN COMMENT 'Indicates whether this cost center is in scope for Sarbanes-Oxley (SOX) internal control testing and audit (True = SOX relevant). SOX-relevant cost centers require documented controls, segregation of duties, and periodic management certification per SOX Sections 302 and 404.',
    `valid_from` DATE COMMENT 'Date from which this cost center is active and eligible to receive cost postings in SAP CO. Defines the start of the cost centers validity period for budget planning, actual cost collection, and period-end closing.',
    `valid_to` DATE COMMENT 'Date until which this cost center is active and eligible to receive cost postings. After this date, the cost center is locked for new postings. Null indicates an open-ended validity period. Used for fiscal year planning and organizational restructuring.',
    CONSTRAINT pk_cost_center PRIMARY KEY(`cost_center_id`)
) COMMENT 'SAP CO cost center master representing an organizational unit responsible for incurring costs — e.g., venue operations, broadcast production, athlete performance, league administration, merchandise fulfillment. Tracks cost center hierarchy, responsible manager, controlling area, validity period, and budget allocation. SSOT for cost accountability across all Sports Entertainment business units.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`profit_center` (
    `profit_center_id` BIGINT COMMENT 'Unique surrogate identifier for the profit center record in the Databricks Silver Layer. Primary key generated by the lakehouse ingestion pipeline from SAP CO master data.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Profit centers in SAP CO belong to a specific company code (legal entity). The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.company_cod',
    `league_id` BIGINT COMMENT 'FK to league.league',
    `venue_id` BIGINT COMMENT 'FK to venue.venue',
    `annual_capex_budget` DECIMAL(18,2) COMMENT 'Approved annual capital expenditure budget for this profit center in local currency. Relevant for venue operations and broadcast infrastructure profit centers. Used in FP&A and SEC capital allocation disclosures.',
    `annual_opex_budget` DECIMAL(18,2) COMMENT 'Approved annual operating expenditure budget for this profit center in local currency, as set in Workday Adaptive Planning. Includes direct costs and allocated overhead. Used for EBITDA margin planning and cost control.',
    `annual_revenue_budget` DECIMAL(18,2) COMMENT 'Approved annual revenue budget for this profit center in the profit centers local currency, as set in Workday Adaptive Planning FP&A. Used for budget vs. actual variance analysis and EBITDA forecasting.',
    `arr_tracking_flag` BOOLEAN COMMENT 'Indicates whether this profit center tracks Annual Recurring Revenue (ARR) as a primary financial metric. Applicable to OTT streaming, digital subscription, and DTC platform profit centers where ARR is a key investor KPI.',
    `broadcast_rights_type` STRING COMMENT 'Classification of broadcast rights revenue stream associated with this profit center where applicable. Drives revenue recognition treatment under ASC 606 for media rights deals. Values: RSN (Regional Sports Network), national_tv, OTT (Over-The-Top Streaming), PPV (Pay-Per-View), international, radio, none. [ENUM-REF-CANDIDATE: rsn|national_tv|ott|ppv|international|radio|none — 7 candidates stripped; promote to reference product]',
    `business_unit_type` STRING COMMENT 'Classification of the revenue-generating business unit represented by this profit center within Sports Entertainments portfolio. Drives EBITDA reporting structure and profitability analysis by segment. [ENUM-REF-CANDIDATE: league_franchise|venue|ott_platform|broadcast_network|merchandise_line|athlete_management|concert_series|sponsorship_unit|corporate — promote to reference product]',
    `controlling_area_code` STRING COMMENT 'SAP Controlling Area code to which this profit center belongs. The controlling area defines the organizational unit within which cost and profit center accounting is performed. Maps to SAP field KOKRS.. Valid values are `^[A-Z0-9]{1,4}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary operating country for this profit center. Drives regulatory compliance requirements (GDPR for EU, CCPA for California), tax treatment, and currency assignment.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this profit center master record was first created in SAP CO. Used for audit trail, data lineage, and SOX control evidence. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the profit centers local reporting currency (e.g., USD, EUR, GBP). Used for EBITDA reporting and currency translation in multi-currency consolidations. Maps to SAP field WAERS.. Valid values are `^[A-Z]{3}$`',
    `department_code` STRING COMMENT 'Organizational department code associated with this profit center, linking it to the functional area within Sports Entertainment (e.g., FINANCE, OPERATIONS, BROADCAST). Maps to SAP field ABTEI.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `elimination_flag` BOOLEAN COMMENT 'Indicates whether postings to this profit center are subject to elimination during group financial consolidation. Prevents double-counting of intercompany revenues and costs in consolidated EBITDA and SEC financial statements.',
    `fiscal_year_variant` STRING COMMENT 'SAP fiscal year variant code defining the fiscal calendar applicable to this profit center (e.g., K4 for calendar year, V3 for April–March). Critical for period-end EBITDA and ARR reporting alignment. Maps to SAP field PERIV.. Valid values are `^[A-Z0-9]{1,2}$`',
    `functional_area_code` STRING COMMENT 'SAP functional area code classifying the profit centers business function for cost-of-sales accounting and P&L by function reporting (e.g., SALES, ADMIN, PRODUCTION, MARKETING). Maps to SAP field FUNC_AREA.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `gl_account_group` STRING COMMENT 'SAP chart of accounts group assigned to this profit center, defining the range of GL accounts permissible for postings. Ensures correct revenue recognition and expense classification per the enterprise chart of accounts.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `hierarchy_level` STRING COMMENT 'Numeric depth of this profit center within the standard hierarchy tree (1 = enterprise root, 2 = segment, 3 = business unit, 4 = sub-unit). Used for hierarchical aggregation in EBITDA and FP&A reporting.',
    `hierarchy_node_code` STRING COMMENT 'Code of the profit center group/node in the standard hierarchy (SAP EC-PCA hierarchy) to which this profit center belongs. Enables roll-up reporting from individual profit centers to business segments and enterprise level. Maps to SAP field KHINR.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `intercompany_flag` BOOLEAN COMMENT 'Indicates whether this profit center participates in intercompany transactions and settlements between legal entities within the Sports Entertainment group. When True, intercompany elimination rules apply during consolidation. Maps to SAP intercompany indicator.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this profit center master record in SAP CO. Supports change tracking, audit trail requirements, and incremental data pipeline processing in the Databricks Silver Layer. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `manager` STRING COMMENT 'Name or employee ID of the person responsible for the profit centers financial performance and budget accountability. Used for management reporting, variance analysis, and SOX control ownership. Maps to SAP field VERAK.',
    `nil_revenue_eligible` BOOLEAN COMMENT 'Indicates whether this profit center is eligible to record NIL (Name, Image, and Likeness) revenue streams from athlete endorsement and licensing arrangements. Relevant for athlete management and league franchise profit centers under NCAA and professional league NIL rules.',
    `profit_center_code` STRING COMMENT 'The externally-known alphanumeric code that uniquely identifies the profit center within the SAP CO controlling area. Used in journal entries, cost allocations, and EBITDA reporting (e.g., PC-NBA-LAL, PC-OTT-001, PC-VENUE-MSG). Maps to SAP field PRCTR.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `profit_center_description` STRING COMMENT 'Long-form business description of the profit centers purpose, scope, and the revenue-generating activities it encompasses. Provides context for financial analysts, auditors, and FP&A teams. Maps to SAP field LTEXT.',
    `profit_center_name` STRING COMMENT 'Full descriptive name of the profit center as defined in SAP CO master data (e.g., Los Angeles Lakers Franchise, OTT Streaming Platform - North America, Madison Square Garden Venue Operations). Maps to SAP field KTEXT.',
    `profit_center_status` STRING COMMENT 'Current lifecycle status of the profit center in SAP CO. active = postings allowed; locked = postings blocked (e.g., during restructuring); inactive = not yet activated; archived = historical record retained for audit. Maps to SAP field LOCK_IND and activation status.. Valid values are `active|inactive|locked|pending_activation|archived`',
    `region_code` STRING COMMENT 'Geographic region code for this profit center used in regional EBITDA roll-up and management reporting (e.g., NA-EAST, NA-WEST, EMEA, APAC). Supports multi-regional financial analysis for global sports entertainment operations.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `revenue_category` STRING COMMENT 'Primary revenue category for this profit center, classifying the dominant revenue stream for EBITDA reporting and segment analysis. [ENUM-REF-CANDIDATE: ticket_sales|media_rights|sponsorship|merchandise|concessions|digital_subscription|licensing|venue_rental|other — promote to reference product]',
    `sap_changed_by` STRING COMMENT 'SAP user ID of the person who last modified this profit center master record. Required for SOX audit trail and change management controls. Maps to SAP field AENAM.. Valid values are `^[A-Z0-9_]{1,12}$`',
    `sap_created_by` STRING COMMENT 'SAP user ID of the person who created this profit center master record in SAP CO. Required for SOX audit trail and segregation of duties (SoD) compliance. Maps to SAP field ERNAM.. Valid values are `^[A-Z0-9_]{1,12}$`',
    `segment_code` STRING COMMENT 'Financial reporting segment classification code assigned to the profit center for IFRS 8 / ASC 280 segment reporting (e.g., LIVE-EVENTS, BROADCAST, MERCHANDISE, DIGITAL-OTT). Drives SEC segment disclosures. Maps to SAP field SEGMENT.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `short_name` STRING COMMENT 'Abbreviated name of the profit center used in reports, dashboards, and financial statements where space is limited. Maps to SAP field MCTXT.. Valid values are `^.{1,20}$`',
    `sox_control_owner` STRING COMMENT 'Name or employee ID of the designated SOX internal control owner responsible for financial reporting controls associated with this profit center. Required for SOX Section 302/404 compliance documentation and audit evidence.',
    `sox_risk_rating` STRING COMMENT 'SOX financial reporting risk rating assigned to this profit center based on materiality, transaction volume, and complexity. Determines the frequency and depth of internal control testing required by the external auditor.. Valid values are `high|medium|low|not_applicable`',
    `target_ebitda_margin_pct` DECIMAL(18,2) COMMENT 'Planned EBITDA margin percentage for this profit center as a target set during annual budgeting in Workday Adaptive Planning. Expressed as a percentage of revenue. Used as the primary KPI for profitability performance management.',
    `valid_from` DATE COMMENT 'Date from which this profit center is effective and postings are permitted in SAP CO. Aligns with fiscal year activation. Maps to SAP field DATAB.',
    `valid_to` DATE COMMENT 'Date until which this profit center is effective. A value of 9999-12-31 indicates an open-ended, indefinitely active profit center. Maps to SAP field DATBI.',
    CONSTRAINT pk_profit_center PRIMARY KEY(`profit_center_id`)
) COMMENT 'SAP CO profit center master representing a revenue-generating business unit — e.g., a specific league franchise, venue, OTT streaming platform, or merchandise line. Enables EBITDA reporting and profitability analysis at the business segment level. Stores profit center hierarchy, controlling area, company code assignment, and segment classification.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`company_code` (
    `company_code_id` BIGINT COMMENT 'Unique surrogate key for the company code record in the Sports Entertainment lakehouse Silver layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `accounting_standard` STRING COMMENT 'The accounting standard framework applied to the financial statements of this company code. US_GAAP for SEC-registered US entities, IFRS for international subsidiaries, LOCAL_GAAP for statutory reporting in specific jurisdictions.. Valid values are `US_GAAP|IFRS|LOCAL_GAAP`',
    `business_area` STRING COMMENT 'SAP S/4HANA business area code assigned to this company code for cross-company-code segment reporting. Represents a distinct business segment such as League Operations, Broadcast, Venue Management, or Merchandise. Supports EBITDA reporting by business segment per SEC ASC 280.. Valid values are `^[A-Z0-9]{4}$`',
    `chart_of_accounts` STRING COMMENT 'Four-character SAP S/4HANA chart of accounts key assigned to this company code (e.g., SPRT). Defines the general ledger account structure, account groups, and account number ranges used for all financial postings. Required for SOX-compliant financial controls and SEC reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `city` STRING COMMENT 'City of the registered office or principal place of business. Used in conjunction with street address for regulatory filings and legal correspondence.',
    `company_code_code` STRING COMMENT 'The four-character alphanumeric SAP S/4HANA company code that uniquely identifies the legal entity within the enterprise organizational structure. Aligns with the SAP FI company code field (BUKRS). Used in all intercompany postings, chart of accounts assignments, and SEC financial reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `company_code_status` STRING COMMENT 'Current lifecycle status of the company code within the SAP S/4HANA organizational structure. Controls whether new financial postings, purchase orders, and sales documents can be created against this entity. in_liquidation triggers SOX disclosure requirements.. Valid values are `active|inactive|in_liquidation|dormant|pending_registration`',
    `consolidation_unit` STRING COMMENT 'The consolidation unit identifier in SAP S/4HANA Group Reporting that maps this company code to the group consolidation structure. Used for automated intercompany elimination, minority interest calculation, and SEC consolidated financial statement preparation.',
    `controlling_area` STRING COMMENT 'Four-character SAP S/4HANA Controlling (CO) area code to which this company code is assigned. The controlling area is the organizational unit for cost accounting, cost center hierarchies, internal orders, and EBITDA reporting. A single controlling area may span multiple company codes for consolidated management reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction in which the legal entity is incorporated (e.g., USA, GBR, DEU). Determines applicable tax law, regulatory reporting obligations (GDPR, CCPA), and functional currency assignment.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the company code master record was first created in the SAP S/4HANA system or the lakehouse Silver layer. Used for audit trail, SOX compliance, and data lineage tracking.',
    `credit_control_area` STRING COMMENT 'SAP S/4HANA credit control area assigned to this company code, governing credit limit management for sponsorship deals, broadcast rights receivables, and merchandise licensing. Controls credit exposure across the SD (Sales and Distribution) module.. Valid values are `^[A-Z0-9]{4}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code representing the local (functional) currency of the company code (e.g., USD, EUR, GBP). All financial postings in SAP S/4HANA FI are recorded in this currency as the primary valuation currency. Critical for EBITDA and ARR reporting.. Valid values are `^[A-Z]{3}$`',
    `deactivation_date` DATE COMMENT 'The date on which the company code was deactivated or blocked in SAP S/4HANA, preventing new financial postings. Populated when an entity is dissolved, merged, or placed in liquidation. Null for active entities.',
    `document_number_range` STRING COMMENT 'SAP S/4HANA document number range interval assigned to this company code for financial document numbering. Ensures sequential, gap-free document numbering required for SOX audit trails and SEC financial reporting integrity.. Valid values are `^[A-Z0-9]{2}$`',
    `entity_type` STRING COMMENT 'Classification of the legal entity by its primary business function within the Sports Entertainment enterprise. Drives intercompany settlement rules, revenue recognition policies, and segment reporting. [ENUM-REF-CANDIDATE: league_operating_company|broadcast_network|venue_management|athlete_management|merchandise_licensing|holding_company|joint_venture — promote to reference product]',
    `field_status_variant` STRING COMMENT 'SAP S/4HANA field status variant assigned to this company code, controlling which fields are required, optional, or suppressed during financial document entry. Enforces data quality standards for SOX-compliant financial postings.. Valid values are `^[A-Z0-9]{4}$`',
    `fiscal_year_variant` STRING COMMENT 'Two-character SAP S/4HANA fiscal year variant code that defines the fiscal year structure for this company code (e.g., K4 for calendar year, V3 for April–March). Governs period-end closing, financial statement preparation, and FP&A planning cycles in Workday Adaptive Planning.. Valid values are `^[A-Z0-9]{2}$`',
    `functional_currency_code` STRING COMMENT 'ISO 4217 functional currency code as defined under IFRS IAS 21 or US GAAP ASC 830, representing the currency of the primary economic environment in which the entity operates. May differ from local currency for entities with predominantly USD-denominated broadcast rights or sponsorship revenues.. Valid values are `^[A-Z]{3}$`',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether this company code is subject to GDPR obligations due to operating in or processing personal data of EU residents. Triggers data privacy controls, fan data consent management, and Data Protection Officer (DPO) assignment requirements.',
    `group_currency_code` STRING COMMENT 'ISO 4217 currency code for the group (parent) reporting currency used in consolidated financial statements (e.g., USD for the Sports Entertainment parent). All company code financials are translated to this currency for SEC consolidated reporting and EBITDA roll-up.. Valid values are `^[A-Z]{3}$`',
    `hard_currency_code` STRING COMMENT 'ISO 4217 currency code for the hard currency (index currency) used in high-inflation countries per SAP S/4HANA parallel valuation. Applicable for Sports Entertainment entities operating in hyperinflationary economies per IFRS IAS 29.. Valid values are `^[A-Z]{3}$`',
    `incorporation_date` DATE COMMENT 'The date on which the legal entity was formally incorporated or registered with the relevant government authority. Used in SEC filings, SOX attestations, and legal entity lifecycle management.',
    `intercompany_clearing_account` STRING COMMENT 'General ledger account number used for intercompany clearing transactions between Sports Entertainment subsidiaries (e.g., broadcast rights fees from broadcast network entity to league operating company). Critical for SOX-compliant intercompany elimination in consolidated SEC reporting.. Valid values are `^[0-9]{6,10}$`',
    `language_key` STRING COMMENT 'ISO 639-1 two-letter language code representing the primary business language for this company code in SAP S/4HANA (e.g., EN, DE, FR). Governs the language used for financial documents, correspondence, and system output for this entity.. Valid values are `^[A-Z]{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the company code master record. Supports change data capture (CDC) in the Databricks lakehouse pipeline and SOX-compliant audit trail for financial master data changes.',
    `legal_entity_identifier` STRING COMMENT '20-character ISO 17442 Legal Entity Identifier (LEI) assigned by a Local Operating Unit (LOU) for publicly traded or regulated Sports Entertainment entities. Required for SEC financial reporting, derivatives reporting under Dodd-Frank, and international regulatory filings.. Valid values are `^[A-Z0-9]{20}$`',
    `legal_name` STRING COMMENT 'The full registered legal name of the Sports Entertainment subsidiary or operating company as filed with the relevant government authority (e.g., Sports Entertainment Broadcast Network LLC, League Operating Company Inc.). Used in SEC filings, SOX attestations, and intercompany agreements.',
    `minority_interest_pct` DECIMAL(18,2) COMMENT 'Percentage of the legal entitys equity not owned by the Sports Entertainment parent, representing non-controlling interest. Used in SEC consolidated financial statements for minority interest disclosure and EBITDA attribution. Range 0.00 to 100.00.',
    `parent_company_code` STRING COMMENT 'The SAP S/4HANA company code of the immediate parent entity in the legal entity hierarchy. Enables hierarchical traversal of the Sports Entertainment corporate structure for intercompany settlement, consolidation, and segment reporting. Null for the ultimate parent holding company.. Valid values are `^[A-Z0-9]{4}$`',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the registered office address. Used for tax jurisdiction determination, regulatory filings, and ADA venue accessibility compliance mapping.',
    `posting_period_variant` STRING COMMENT 'SAP S/4HANA posting period variant assigned to this company code, controlling which fiscal periods are open or closed for financial postings. Enforces period-end close discipline and SOX-compliant financial controls by preventing backdated entries.. Valid values are `^[A-Z0-9]{4}$`',
    `profit_center_standard_hierarchy` STRING COMMENT 'Name of the SAP S/4HANA profit center standard hierarchy node to which this company codes profit centers are assigned. Enables segment-level EBITDA reporting and management accounting roll-ups across league, broadcast, venue, and merchandise business units.',
    `region_code` STRING COMMENT 'ISO 3166-2 state, province, or region code of the registered office (e.g., NY, CA, TX). Used for state tax compliance, CCPA applicability determination, and regulatory jurisdiction mapping.. Valid values are `^[A-Z]{2,3}$`',
    `sec_reporting_entity` BOOLEAN COMMENT 'Indicates whether this company code is a registrant or consolidated subsidiary required to be included in SEC financial filings (10-K, 10-Q, 8-K). Drives inclusion in the consolidation perimeter for group financial reporting.',
    `short_name` STRING COMMENT 'Abbreviated or trading name of the legal entity used in internal reporting, dashboards, and ERP display fields. Corresponds to SAP S/4HANA company code short text (KTEXT). Distinct from the full legal name.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this company code master record was sourced. Primarily SAP S/4HANA FI/CO for financial master data. Supports data lineage, reconciliation, and Silver layer provenance tracking in the Databricks lakehouse.. Valid values are `SAP_S4HANA|WORKDAY|MANUAL`',
    `sox_relevant` BOOLEAN COMMENT 'Indicates whether this company code is within scope for Sarbanes-Oxley (SOX) Section 302 and 404 internal control assessments. True for all entities included in the consolidated SEC financial statements of the publicly traded Sports Entertainment parent.',
    `street_address` STRING COMMENT 'Street address of the registered office or principal place of business for the legal entity. Used in SEC filings, regulatory correspondence, and legal notices. Classified as confidential organizational contact data.',
    `tax_registration_number` STRING COMMENT 'Government-issued tax identification number for the legal entity (e.g., US Employer Identification Number (EIN), EU VAT registration number). Required for tax filings, vendor invoicing, and regulatory reporting. Stored as confidential business data.',
    `vat_registration_number` STRING COMMENT 'Value Added Tax (VAT) registration number for entities operating in VAT-applicable jurisdictions (EU, UK, etc.). Used on broadcast rights invoices, sponsorship agreements, and merchandise licensing contracts. Distinct from the domestic tax registration number.',
    CONSTRAINT pk_company_code PRIMARY KEY(`company_code_id`)
) COMMENT 'Legal entity master record within the SAP S/4HANA organizational structure. Represents each incorporated Sports Entertainment subsidiary or operating company (e.g., league operating company, broadcast network entity, venue management LLC). Stores company code, legal name, country, currency, fiscal year variant, and chart of accounts assignment. Required for SOX-compliant intercompany and SEC reporting.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`journal_entry` (
    `journal_entry_id` BIGINT COMMENT 'Unique surrogate identifier for each journal entry record in the Silver Layer lakehouse. Primary key for this data product. Role: TRANSACTION_HEADER.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Journal entries in SAP FI are posted within a specific company code (legal entity). The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.co',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP Controlling (CO) cost center to which this journal entry is allocated. Enables cost allocation reporting by business unit (e.g., Venue Operations, Broadcast, Athlete Management). Corresponds to BSEG.KOSTL.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Journal entries are posted to specific fiscal periods. The fiscal_year and fiscal_period INT columns are denormalized attributes that should be retrieved via JOIN to fiscal_period master table. This n',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: In SAP FI-AA, asset-related journal entries (depreciation postings, acquisition postings, disposal postings, impairment charges) are linked to specific fixed asset records. journal_entry does not curr',
    `gl_account_id` BIGINT COMMENT 'Reference to the primary GL account associated with this journal entry header. For multi-line entries, this represents the controlling or summary account. Detailed line-item GL accounts are embedded within the line item attributes of this product. Links to the chart of accounts master data.',
    `ledger_id` BIGINT COMMENT 'Two-character identifier of the SAP New GL ledger to which this entry is posted (e.g., 0L = leading ledger GAAP, L1 = IFRS parallel ledger, L2 = local GAAP ledger). Supports parallel accounting for multi-GAAP reporting requirements.',
    `profit_center_id` BIGINT COMMENT 'Reference to the SAP Controlling profit center representing the business segment responsible for this posting (e.g., NFL Division, Concert Touring, OTT Streaming). Enables EBITDA reporting by profit center and segment reporting per IFRS 8. Corresponds to BSEG.PRCTR.',
    `controlling_area` STRING COMMENT 'Four-character SAP Controlling (CO) area code grouping company codes for management accounting and internal reporting. Defines the scope for cost center, profit center, and internal order reporting within Sports Entertainment. Corresponds to BKPF.KOKRS.. Valid values are `^[A-Z0-9]{4}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code of the transaction currency in which this journal entry was originally recorded (e.g., USD, EUR, GBP). Part of the MONETARY_TRIPLET. Corresponds to BKPF.WAERS.. Valid values are `^[A-Z]{3}$`',
    `document_date` DATE COMMENT 'The date of the originating source document (e.g., invoice date, payment date, contract date) that triggered this journal entry. May differ from posting date when documents are processed with a lag. Corresponds to BKPF.BLDAT.',
    `document_number` STRING COMMENT 'SAP-assigned ten-digit accounting document number uniquely identifying the journal entry within a company code and fiscal year. This is the externally-known business identifier used in audit trails, reconciliations, and cross-system references. Corresponds to BKPF.BELNR.. Valid values are `^[0-9]{10}$`',
    `document_type` STRING COMMENT 'Two-character SAP document type code classifying the nature of the journal entry (e.g., SA=GL posting, KR=vendor invoice, DZ=customer payment, AB=accrual, IC=intercompany, AA=asset posting, ZP=payment run). Drives number range assignment and account type restrictions. [ENUM-REF-CANDIDATE: SA|KR|DZ|AB|IC|AA|ZP|RE|KZ|DR — promote to reference product]. Valid values are `^[A-Z0-9]{2}$`',
    `entry_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this journal entry record was first created in SAP FI. Serves as the RECORD_AUDIT_CREATED field for audit trail and SOX compliance. Corresponds to BKPF.CPUDT + BKPF.CPUTM.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied to translate the transaction currency amount to local currency at the time of posting. Sourced from SAP exchange rate tables. Corresponds to BKPF.KURSF.',
    `functional_area` STRING COMMENT 'SAP functional area code classifying the business function of this posting for cost-of-sales accounting (e.g., SALES, MKTG, ADMIN, PROD, R&D). Supports income statement presentation by function of expense per IFRS IAS 1. Corresponds to BSEG.FKBER.. Valid values are `^[A-Z0-9]{4,16}$`',
    `group_currency_amount` DECIMAL(18,2) COMMENT 'Total amount of the journal entry translated into the group (consolidation) currency (typically USD for Sports Entertainment). Used for consolidated EBITDA reporting, SEC filings, and group-level financial analysis. Corresponds to the aggregate of BSEG.KZBTR.',
    `header_text` STRING COMMENT 'Free-text description at the journal entry header level providing business context for the posting (e.g., Q3 Ticket Revenue Accrual — NFL Season, Broadcast Rights Amortization — RSN Deal, Intercompany Settlement — Venue Ops). Corresponds to BKPF.BKTXT.',
    `intercompany_indicator` BOOLEAN COMMENT 'Flag indicating whether this journal entry represents an intercompany transaction between two legal entities within the Sports Entertainment group (True) or an external third-party transaction (False). Critical for consolidation elimination and intercompany reconciliation.',
    `internal_order_number` STRING COMMENT 'SAP CO internal order number used to track costs and revenues for specific projects or events (e.g., a specific concert tour, stadium renovation project, or broadcast production). Enables project-level P&L and budget vs. actual analysis. Corresponds to BSEG.AUFNR.',
    `last_changed_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this journal entry record. Serves as the RECORD_AUDIT_UPDATED field for change tracking and SOX audit trail. Corresponds to BKPF.AEDAT.',
    `line_item_count` STRING COMMENT 'Total number of accounting line items (debit and credit rows) embedded within this journal entry document. A balanced double-entry posting requires a minimum of two line items. Supports validation of entry completeness and complexity classification.',
    `local_currency_amount` DECIMAL(18,2) COMMENT 'Total amount of the journal entry translated into the company code local (functional) currency. Used for statutory financial reporting, balance sheet, and P&L in local GAAP. Part of the MONETARY_TRIPLET. Corresponds to the aggregate of BSEG.DMBTR.',
    `local_currency_code` STRING COMMENT 'ISO 4217 three-letter code for the company code local currency (functional currency) used for statutory reporting. Distinct from transaction currency when cross-currency postings occur. Corresponds to BKPF.HWAER.. Valid values are `^[A-Z]{3}$`',
    `posting_date` DATE COMMENT 'The date on which the journal entry is posted to the general ledger and affects account balances. Determines the fiscal period assignment. Distinct from document date and entry date. Corresponds to BKPF.BUDAT. This is the principal business event date (BUSINESS_EVENT_TIMESTAMP category).',
    `posting_key` STRING COMMENT 'SAP two-digit posting key controlling the debit/credit indicator and account type for the primary line item of this journal entry (e.g., 40=GL debit, 50=GL credit, 01=customer debit, 31=vendor credit). Determines how the entry affects account balances. Corresponds to BSEG.BSCHL.. Valid values are `^[0-9]{2}$`',
    `posting_status` STRING COMMENT 'Current lifecycle state of the journal entry within the SAP FI workflow. posted = fully committed to GL; parked = saved but not yet posted pending approval; held = incomplete draft; reversed = offset by a reversal document; simulated = test posting not committed; error = failed validation. Serves as the LIFECYCLE_STATUS field.. Valid values are `posted|parked|held|reversed|simulated|error`',
    `reference_document_number` STRING COMMENT 'External reference number linking this journal entry to the originating source document (e.g., vendor invoice number, ticket sales batch ID, broadcast rights contract number, sponsorship deal reference). Enables cross-system traceability. Corresponds to BKPF.XBLNR.',
    `revenue_category` STRING COMMENT 'Business classification of the revenue stream associated with this journal entry, aligned to Sports Entertainment core revenue lines. Enables EBITDA reporting by revenue category and supports ARR tracking for recurring streams. [ENUM-REF-CANDIDATE: ticket_sales|broadcast_rights|sponsorship|merchandise|licensing|ppv|ott_streaming|venue_operations|nil_rights|other — promote to reference product]',
    `reversal_document_number` STRING COMMENT 'Document number of the corresponding reversal entry if this journal entry has been reversed, or the original document number if this entry IS the reversal. Null if no reversal relationship exists. Enables audit trail for correction postings. Corresponds to BKPF.STBLG.',
    `reversal_indicator` BOOLEAN COMMENT 'Flag indicating whether this journal entry is a reversal document (True) or an original posting (False). Reversal entries offset prior postings for corrections, accrual reversals, or error remediation. Corresponds to BKPF.STBLG presence.',
    `reversal_reason_code` STRING COMMENT 'SAP two-digit reason code explaining why this journal entry was reversed (e.g., 01=incorrect posting, 02=accrual reversal, 03=period-end correction). Null if not reversed. Corresponds to BKPF.STGRD.. Valid values are `^[0-9]{2}$`',
    `source_system` STRING COMMENT 'Identifier of the originating operational system that generated this journal entry (e.g., SAP_FI for direct GL postings, TICKETMASTER for ticket revenue interfaces, SHOPIFY for merchandise e-commerce, WORKDAY for payroll postings, MANUAL for manual journal entries). Supports data lineage and reconciliation.. Valid values are `SAP_FI|TICKETMASTER|SHOPIFY|WORKDAY|MANUAL|INTERFACE`',
    `sox_approval_status` STRING COMMENT 'Current status of the SOX-mandated approval workflow for this journal entry. pending = awaiting approver action; approved = authorized by designated control owner; rejected = returned for correction; escalated = routed to senior approver; exempt = system-generated entry below materiality threshold. Required for SOX Section 404 internal controls over financial reporting.. Valid values are `pending|approved|rejected|escalated|exempt`',
    `sox_approval_timestamp` TIMESTAMP COMMENT 'Date and time when the SOX approval was granted for this journal entry. Null if pending or exempt. Provides immutable audit evidence for SOX Section 404 compliance and external auditor review.',
    `tax_amount` DECIMAL(18,2) COMMENT 'Tax amount (VAT, sales tax, or withholding tax) included in or associated with this journal entry in the transaction currency. Part of the MONETARY_TRIPLET adjustment component. Null for non-taxable postings. Corresponds to BSEG.HWSTE.',
    `tax_code` STRING COMMENT 'SAP two-character tax code applied to this journal entry for VAT, sales tax, or withholding tax calculation (e.g., I1=input tax, O1=output tax, W1=withholding). Null for non-taxable postings. Corresponds to BSEG.MWSKZ.. Valid values are `^[A-Z0-9]{2}$`',
    `trading_partner_code` STRING COMMENT 'Four-character company code of the intercompany trading partner entity when this is an intercompany journal entry. Used for automated intercompany elimination during group consolidation. Null for external transactions. Corresponds to BKPF.VBUND.. Valid values are `^[A-Z0-9]{4}$`',
    `transaction_amount` DECIMAL(18,2) COMMENT 'Gross total amount of the journal entry in the transaction currency. Represents the sum of all debit line items (which must equal the sum of all credit line items for a balanced entry). Part of the MONETARY_TRIPLET. Corresponds to the aggregate of BSEG.WRBTR across line items.',
    CONSTRAINT pk_journal_entry PRIMARY KEY(`journal_entry_id`)
) COMMENT 'Core financial posting document in SAP FI representing a balanced double-entry accounting transaction with embedded line items (posting rows). Each journal entry contains one or more line items specifying GL account, amount, debit/credit indicator, cost center, profit center, and tax code. Captures document type (invoice, payment, accrual, intercompany, allocation), posting date, fiscal period, company code, reference document, posting user, reversal indicator, and SOX approval workflow status. SSOT for all financial movements across the general ledger including revenue recognition postings for ticket sales, broadcast rights, sponsorship, merchandise, and cost allocation postings. Line-item granularity is embedded within this product — no separate line product exists.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`budget` (
    `budget_id` BIGINT COMMENT 'Unique surrogate identifier for the budget planning record in the Databricks Silver Layer. Primary key for the finance.budget data product.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Budgets are scoped to a specific legal entity (company code) in SAP S/4HANA. The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.company_c',
    `contract_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_contract. Business justification: Team salary budgets are planned against specific athlete contracts. Budget records for player payroll must reference the athlete contract driving the budget line, enabling variance analysis between bu',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Budgets in SAP CO are allocated to specific cost centers. The existing cost_center_code string field is a denormalized reference that should be replaced with a proper FK to cost_center.cost_center_id,',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Budgets are allocated and tracked by fiscal period. The fiscal_year and fiscal_period columns are denormalized temporal attributes that should be normalized via FK to fiscal_period master.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Budget line items are posted against specific GL accounts in the chart of accounts. The gl_account_code string field is a denormalized reference that should be replaced with a typed FK to gl_account.g',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: In SAP S/4HANA, budgets are maintained against specific ledgers (leading ledger, extension ledger for parallel accounting under IFRS/GAAP). The budget table has no ledger_id FK despite the ledger bein',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Rights fee payments are planned in finance budgets with budget lines referencing specific deals for rights fee expenditure planning and budget vs. actuals variance analysis. Finance budget controllers',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Budgets are also allocated at the profit center level in SAP CO. The profit_center_code string field is a denormalized reference that should be replaced with a typed FK to profit_center.profit_center_',
    `actuals_amount` DECIMAL(18,2) COMMENT 'Actual expenditure or revenue posted to the GL account and cost center year-to-date as of the last data load from SAP FI/CO. Used for budget vs. actuals variance analysis and EBITDA reporting.',
    `approval_date` DATE COMMENT 'Date on which the budget record received final approval in the workflow. Null if not yet approved. Critical for SOX-compliant financial authorization audit trails.',
    `approval_status` STRING COMMENT 'Current workflow approval status of the budget record: draft (in preparation), submitted (pending review), under_review (in approval chain), approved (authorized), rejected (returned for revision), locked (closed for posting). Supports SOX-compliant budget authorization controls.. Valid values are `draft|submitted|under_review|approved|rejected|locked`',
    `budget_name` STRING COMMENT 'Human-readable descriptive name for the budget record (e.g., FY2025 Event Operations OPEX Base Budget). Used in FP&A reporting and investor relations presentations.',
    `budget_number` STRING COMMENT 'Externally-known alphanumeric identifier for the budget record as assigned in Workday Adaptive Planning or SAP CO. Used for cross-system reconciliation and audit traceability.',
    `budget_type` STRING COMMENT 'Classification of the budget by expenditure or revenue category: OPEX (Operating Expenditure), CAPEX (Capital Expenditure), headcount (workforce cost plan), or revenue (income plan). Drives chart of accounts mapping in SAP CO.. Valid values are `opex|capex|headcount|revenue`',
    `business_unit` STRING COMMENT 'Business unit or division to which this budget is attributed (e.g., League Operations, Broadcast Network, Venue Management, Fan Engagement). Supports segment-level EBITDA reporting and investor relations guidance.',
    `committed_amount` DECIMAL(18,2) COMMENT 'Amount of the budget that has been legally committed via purchase orders, contracts, or reservations in SAP MM/SD but not yet invoiced. Represents encumbered funds for budget availability control.',
    `cost_element_code` STRING COMMENT 'SAP CO cost element code that classifies the nature of the planned expenditure (e.g., salaries, venue hire, broadcast rights fees). Enables cost element-level variance analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this budget record was first created in the source system (Workday Adaptive Planning or SAP CO). Supports data lineage and SOX audit trail requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this budget record (e.g., USD, EUR, GBP). Sports Entertainment operates across global markets requiring multi-currency budget management.. Valid values are `^[A-Z]{3}$`',
    `effective_from_date` DATE COMMENT 'The start date from which this budget record is effective and valid for financial planning and posting. Aligns with the fiscal period start date.',
    `effective_to_date` DATE COMMENT 'The end date through which this budget record is effective. Aligns with the fiscal period end date. Used to manage multi-year plan validity windows.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied to convert the budget amount to the group reporting currency (USD). Sourced from SAP FI currency tables at the time of budget load. Relevant for international operations (FIFA, UEFA markets).',
    `forecast_amount` DECIMAL(18,2) COMMENT 'Latest rolling forecast amount for the fiscal period as updated in Workday Adaptive Planning. Reflects the most current expectation of financial outcome, incorporating actuals-to-date and revised forward projections.',
    `functional_area` STRING COMMENT 'SAP FI functional area classification for the budget record (e.g., Event Operations, Broadcast, Athlete Management, Venue Operations). Supports functional P&L and SEC segment reporting.',
    `is_intercompany` BOOLEAN COMMENT 'Indicates whether this budget record relates to an intercompany transaction between legal entities within the Sports Entertainment group. True = intercompany; False = third-party. Required for intercompany elimination in consolidated financial reporting.',
    `lock_date` DATE COMMENT 'Date on which the budget record was locked in SAP CO, preventing further manual adjustments. Ensures integrity of the approved baseline for variance reporting.',
    `notes` STRING COMMENT 'Free-text commentary entered by the budget owner or FP&A analyst explaining assumptions, drivers, or variances for this budget record (e.g., Includes incremental broadcast rights cost for new RSN deal). Supports management reporting narratives.',
    `period_granularity` STRING COMMENT 'Indicates whether the budget record is expressed at monthly, quarterly, or annual granularity. Determines how fiscal_period is interpreted in FP&A reporting.. Valid values are `monthly|quarterly|annual`',
    `plan_type` STRING COMMENT 'Distinguishes the planning horizon: annual_budget (single fiscal year), multi_year_plan (3–5 year strategic plan), or rolling_forecast (continuous 12–18 month forward view). Supports FP&A and investor relations cycles.. Valid values are `annual_budget|multi_year_plan|rolling_forecast`',
    `planned_amount` DECIMAL(18,2) COMMENT 'The original planned budget amount for the fiscal period in the transaction currency. Represents the baseline financial commitment approved at the start of the planning cycle. Core field for FP&A variance analysis.',
    `prior_year_actual_amount` DECIMAL(18,2) COMMENT 'Actual amount posted for the equivalent fiscal period in the prior fiscal year. Used as a benchmark for year-over-year variance analysis and budget calibration in FP&A.',
    `reporting_currency_amount` DECIMAL(18,2) COMMENT 'Planned amount translated to the group reporting currency (USD) using the exchange_rate. Enables consolidated EBITDA reporting and SEC financial disclosures across multi-currency global operations.',
    `revised_amount` DECIMAL(18,2) COMMENT 'The most recently approved revised budget amount for the fiscal period, reflecting mid-year budget amendments or reforecasts. Null if no revision has been approved.',
    `scenario_type` STRING COMMENT 'Financial planning scenario classification: base (most likely), upside (optimistic), downside (pessimistic), or stress (extreme adverse). Used for EBITDA projections and investor relations guidance.. Valid values are `base|upside|downside|stress`',
    `source_system` STRING COMMENT 'Identifies the originating system of record for this budget record: Workday Adaptive Planning (primary FP&A tool), SAP CO (controlling module), or manual (spreadsheet-based override). Supports data lineage in the lakehouse.. Valid values are `workday_adaptive|sap_co|manual`',
    `submission_date` DATE COMMENT 'Date on which the budget record was formally submitted for approval in Workday Adaptive Planning. Supports FP&A calendar management and SOX audit trail.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this budget record in the source system. Used for incremental data loads into the Databricks Silver Layer and change tracking.',
    `variance_explanation` STRING COMMENT 'Structured narrative provided by the budget owner explaining material variances between planned and actual amounts. Required for FP&A monthly close reporting and investor relations commentary.',
    `version` STRING COMMENT 'Version label of the budget or forecast cycle (e.g., Original, Revised, Q1 Reforecast, Q2 Reforecast, Q3 Reforecast, Q4 Reforecast). Tracks the evolution of financial plans across the fiscal year. [ENUM-REF-CANDIDATE: original|revised|q1_reforecast|q2_reforecast|q3_reforecast|q4_reforecast — promote to reference product]',
    CONSTRAINT pk_budget PRIMARY KEY(`budget_id`)
) COMMENT 'Financial planning record encompassing annual budgets, multi-year plans, and rolling forecasts per cost center, profit center, or WBS element. Managed in Workday Adaptive Planning and loaded into SAP CO. Captures budget/forecast version (original, revised, Q1-Q4 reforecast), scenario type (base, upside, downside), budget type (OPEX, CAPEX), fiscal year/period, planned amounts by GL account and cost element at monthly/quarterly granularity, committed amounts, actuals-to-date, and approval workflow status. Supports FP&A variance analysis, rolling forecast cycles, EBITDA projections, and investor relations guidance for Sports Entertainment.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`ar_invoice` (
    `ar_invoice_id` BIGINT COMMENT 'Unique surrogate identifier for the accounts receivable invoice record in the Databricks Silver Layer. Primary key for this entity.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: AR invoices are issued by a specific legal entity (company code) in SAP FI. The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.company_co',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP CO cost center (KOSTL) responsible for the revenue-generating activity billed on this invoice. Supports expense allocation, profitability analysis (CO-PA), and FP&A reporting.',
    `account_id` BIGINT COMMENT 'Reference to the customer master record (debtor/payer) in the AR sub-ledger. Corresponds to the SAP FI-AR customer (KUNNR) account to whom the invoice is issued — sponsors, broadcast rights licensees, merchandise wholesale buyers, or premium suite holders.',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: AR invoices for sponsorship billing must reference the originating deal for revenue tracking, dispute resolution, and collections. Sports finance teams run deal-level AR aging reports and reconcile in',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: AR invoices are posted to fiscal periods for revenue recognition and financial reporting. Normalizes fiscal_year and fiscal_period INT columns.',
    `gl_account_id` BIGINT COMMENT 'Reference to the GL account (HKONT) in the chart of accounts to which this invoices revenue is posted. Enables drill-through from AR sub-ledger to the general ledger for SOX-compliant financial controls and SEC reporting.',
    `group_sale_id` BIGINT COMMENT 'Foreign key linking to ticketing.group_sale. Business justification: Group sales generate AR invoices for deposits and final payments. Linking ar_invoice to group_sale enables group sales billing reconciliation, payment tracking against negotiated terms, and collection',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: In SAP FI, every AR invoice posting generates a corresponding journal entry (FI document). ar_invoice has reference_document_number (STRING) but no structured FK to finance.journal_entry. Adding journ',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Media rights deals generate AR invoices for licensee rights fee payments. Finance tracks receivables per deal for cash collections, dunning, and revenue reconciliation. The existing contract_id on ar_',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: Membership fee invoicing (season tickets, VIP, corporate) is a core AR process. Finance must link AR invoices to the membership record for revenue recognition, dunning management, billing dispute reso',
    `profit_center_id` BIGINT COMMENT 'Reference to the SAP CO profit center (PRCTR) for segment-level P&L attribution. Enables EBITDA reporting by business unit (e.g., league operations, broadcast, venue, merchandise).',
    `season_ticket_account_id` BIGINT COMMENT 'Foreign key linking to ticketing.season_ticket_account. Business justification: AR invoices are generated for season ticket account billing (installment payment schedules, renewal invoices). Linking ar_invoice to season_ticket_account enables STH billing reconciliation, dunning m',
    `ticket_order_id` BIGINT COMMENT 'Foreign key linking to ticketing.ticket_order. Business justification: AR invoices are generated for ticket orders in B2B/corporate ticketing, group sales invoicing, and season ticket billing. Linking ar_invoice to ticket_order enables A/R collections teams to trace invo',
    `amount_paid` DECIMAL(18,2) COMMENT 'Cumulative amount received from the customer against this invoice to date. Enables partial payment tracking and outstanding balance calculation (net_amount - amount_paid). Updated upon each payment clearing in SAP FI-AR.',
    `billing_date` DATE COMMENT 'The date on which the invoice was issued and sent to the customer. Represents the principal business event date for revenue recognition purposes. Maps to SAP FKDAT (billing date on SD billing document) or BLDAT (document date on FI posting).',
    `clearing_document_number` STRING COMMENT 'SAP FI clearing document number (AUGBL) assigned when the invoice is fully or partially cleared by a payment, credit memo, or write-off. Null if the invoice remains open. Provides the AR-to-payment audit trail.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this AR invoice record was first created in the source system (SAP FI-AR). Provides the audit trail creation point for SOX compliance and data lineage in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the invoice document currency (WAERS in SAP). Sports Entertainment operates across global markets; invoices may be denominated in USD, EUR, GBP, AUD, etc.. Valid values are `^[A-Z]{3}$`',
    `deferred_revenue_amount` DECIMAL(18,2) COMMENT 'Portion of the gross_amount that has been billed but not yet recognized as revenue because the associated performance obligation (e.g., season sponsorship activation, multi-year broadcast rights) has not been fully satisfied. Feeds the deferred revenue liability on the balance sheet.',
    `discount_amount` DECIMAL(18,2) COMMENT 'Early-payment or contractual discount amount applied to the invoice per the payment terms (SKTO1/SKTO2 in SAP). Relevant for sponsor and broadcast rights deals with negotiated discount schedules.',
    `dispute_reason_code` STRING COMMENT 'Standardized code identifying the reason a customer has disputed this invoice (e.g., pricing discrepancy, delivery shortfall, contract breach). Populated when payment_status = disputed. Supports AR dispute management workflow in SAP FI-AR Collections Management.. Valid values are `^[A-Z0-9]{2,6}$`',
    `due_date` DATE COMMENT 'The date by which payment must be received from the customer per the agreed payment terms. Drives dunning runs, cash flow forecasting, and DSO (Days Sales Outstanding) calculations in SAP FI-AR.',
    `dunning_block` BOOLEAN COMMENT 'Indicates whether dunning is blocked for this invoice (MANSP in SAP). True = dunning is suppressed (e.g., invoice under dispute or special arrangement). False = dunning proceeds normally.',
    `dunning_date` DATE COMMENT 'Date on which the most recent dunning notice was issued to the customer for this invoice (MADAT in SAP). Used to schedule the next dunning run and track collections escalation timeline.',
    `dunning_level` STRING COMMENT 'Current dunning level (MAHNS in SAP, 0–4) indicating how many dunning notices have been sent to the customer for this overdue invoice. Level 0 = no dunning; Level 4 = final notice / legal escalation. Drives collections workflow.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate (KURSF in SAP) applied at the time of invoice posting to convert the document currency to the company code local currency. Required for multi-currency consolidation and SEC financial reporting.',
    `gross_amount` DECIMAL(18,2) COMMENT 'Total invoice amount before tax deductions. Represents the full billed value of goods or services rendered (e.g., sponsorship activation fee, broadcast rights license fee). Maps to SAP WRBTR (amount in document currency) on the AR line item.',
    `intercompany_flag` BOOLEAN COMMENT 'Indicates whether this invoice is an intercompany transaction between two Sports Entertainment legal entities (True) or an external customer invoice (False). Intercompany invoices require elimination in consolidated financial statements per SOX and SEC reporting.',
    `invoice_number` STRING COMMENT 'Externally-visible, human-readable invoice document number assigned by SAP FI-AR (e.g., AR-202400012345). Used on billing documents sent to sponsors, broadcast licensees, merchandise wholesale buyers, and premium suite holders. Maps to SAP BELNR field on BKPF/VBRK.. Valid values are `^[A-Z]{2,4}-[0-9]{8,12}$`',
    `invoice_type` STRING COMMENT 'Classification of the invoice document type. standard = regular customer invoice; credit_memo = reduction of a prior invoice; debit_memo = additional charge; pro_forma = non-posting preview invoice; intercompany = settlement between Sports Entertainment legal entities.. Valid values are `standard|credit_memo|debit_memo|pro_forma|intercompany`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this AR invoice record in the source system. Tracks changes to payment status, dunning level, dispute flags, and amount adjustments. Required for incremental data pipeline processing and SOX audit trail.',
    `local_currency_amount` DECIMAL(18,2) COMMENT 'Net invoice amount converted to the company codes local (functional) currency using the exchange_rate at posting date. Used for consolidated financial reporting and EBITDA calculations in the reporting currency.',
    `net_amount` DECIMAL(18,2) COMMENT 'Net payable amount after tax (gross_amount + tax_amount). This is the total amount the customer owes. Used for cash flow forecasting, DSO calculation, and revenue recognition reporting.',
    `payment_block` BOOLEAN COMMENT 'Indicates whether the invoice is blocked from being cleared by an incoming payment (ZLSPR in SAP). True = payment blocked pending resolution (e.g., dispute, credit check). False = payment can be applied.',
    `payment_date` DATE COMMENT 'Date on which the invoice was fully cleared/paid in SAP FI-AR (AUGDT). Null if not yet paid. Used for DSO calculation, cash flow actuals, and AR aging analysis.',
    `payment_status` STRING COMMENT 'Current lifecycle status of the invoice from an AR collections perspective. open = unpaid and within terms; partially_paid = partial payment received; paid = fully settled; overdue = past due_date; disputed = customer raised a dispute; cancelled = invoice voided; written_off = deemed uncollectable. [ENUM-REF-CANDIDATE: open|partially_paid|paid|overdue|disputed|cancelled|written_off — promote to reference product]',
    `payment_terms_code` STRING COMMENT 'SAP payment terms key (ZTERM) defining the discount and net payment schedule (e.g., NT30 = net 30 days, 2/10NT30 = 2% discount if paid within 10 days). Determines due_date calculation and early-payment discount eligibility.. Valid values are `^[A-Z0-9]{2,4}$`',
    `posting_date` DATE COMMENT 'The date on which the invoice was posted to the general ledger (SAP BUDAT). May differ from billing_date when invoices are back-dated or posted in a subsequent period. Critical for period-close accuracy and SOX controls.',
    `reference_document_number` STRING COMMENT 'External reference number provided by the customer (e.g., purchase order number, contract reference, deal ID from Salesforce CRM). Maps to SAP XBLNR field. Enables customer-side reconciliation and dispute resolution.',
    `revenue_category` STRING COMMENT 'Business classification of the revenue stream being billed. Aligns with Sports Entertainments primary revenue lines: sponsorship fees, broadcast rights licensing, merchandise wholesale, premium suite/hospitality, ticketing, and IP licensing. Supports EBITDA reporting by revenue segment. [ENUM-REF-CANDIDATE: sponsorship|broadcast_rights|merchandise_wholesale|premium_suite|ticketing|licensing|other — promote to reference product]',
    `revenue_recognition_status` STRING COMMENT 'Indicates the ASC 606 / IFRS 15 revenue recognition status of this invoice. pending = performance obligation not yet satisfied; recognized = revenue fully recognized; deferred = billed in advance of performance; partially_recognized = multi-element arrangement partially satisfied.. Valid values are `pending|recognized|deferred|partially_recognized`',
    `sap_document_type` STRING COMMENT 'SAP FI document type code (BLART) classifying the accounting document (e.g., RV = billing document transfer, DR = customer invoice, DG = customer credit memo). Preserves source system classification for reconciliation and audit.. Valid values are `^[A-Z]{2}$`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Total tax charged on the invoice (e.g., VAT, GST, sales tax). Calculated by SAP FI tax determination based on the customers tax jurisdiction and the revenue category. Maps to SAP WMWST.',
    `write_off_amount` DECIMAL(18,2) COMMENT 'Amount of the invoice that has been written off as uncollectable bad debt. Populated when payment_status = written_off. Feeds the bad debt expense account and allowance for doubtful accounts on the balance sheet.',
    CONSTRAINT pk_ar_invoice PRIMARY KEY(`ar_invoice_id`)
) COMMENT 'Accounts receivable invoice issued to external customers — sponsors, broadcast rights licensees, merchandise wholesale buyers, and premium suite holders. Stores invoice number, billing date, due date, customer account, payment terms, gross amount, tax amount, net amount, currency, payment status, and dunning level. Managed in SAP FI-AR. SSOT for revenue billing documents.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`ap_invoice` (
    `ap_invoice_id` BIGINT COMMENT 'Unique surrogate identifier for the accounts payable invoice record in the Databricks Silver Layer. Primary key generated by the lakehouse ingestion pipeline from SAP FI-AP.',
    `agent_id` BIGINT COMMENT 'Foreign key linking to athlete.agent. Business justification: AP invoices are issued to agents for commission payments on athlete contracts. Finance teams need agent reference on AP invoices for commission payment processing, 1099 tax reporting, and agent paymen',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: AP invoices are posted within a specific legal entity (company code) in SAP FI. The company_code string field is a denormalized reference that should be replaced with a typed FK to company_code.compan',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP Controlling cost center to which the invoice expense is allocated. Drives EBITDA reporting and FP&A cost attribution across business units (e.g., venue operations, broadcast, athlete management).',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: AP invoices are posted to fiscal periods for financial reporting. Normalizes fiscal_year and fiscal_period INT columns by linking to fiscal_period master table.',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: AP invoices for capital expenditures (CAPEX) are directly linked to fixed asset acquisitions in SAP FI-AA. When a vendor invoice is for a stadium renovation, broadcast equipment purchase, or other cap',
    `gl_account_id` BIGINT COMMENT 'Reference to the general ledger account in the chart of accounts to which this invoice is posted. Determines financial statement line classification for SEC reporting.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: In SAP FI, every AP invoice posting generates a corresponding journal entry (FI document). ap_invoice has sap_document_number (STRING) which references the SAP document but there is no structured FK t',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: AP invoices are generated for NIL agreement payments to athletes or their agents. The ap_invoice must reference the nil_agreement it settles for payment reconciliation, royalty tracking, and NIL compl',
    `officiating_assignment_id` BIGINT COMMENT 'Foreign key linking to event.officiating_assignment. Business justification: Officiating assignments carry fee obligations (officiating_fee_amount, expense_allowance_amount). AP invoices for official payments must reference the specific assignment for three-way match validatio',
    `participant_id` BIGINT COMMENT 'Foreign key linking to event.participant. Business justification: Event participants (athletes, performers) with appearance fees (participant.appearance_fee_amount) generate AP invoices for payment. Finance must link AP invoices to the specific participant engagemen',
    `payment_run_id` BIGINT COMMENT 'SAP automatic payment program run identifier (F110) that processed this invoice for payment. Links the invoice to the payment batch for reconciliation and audit.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: ap_invoice has profit_center_code (STRING) but no FK to finance.profit_center. In SAP FI/CO, every AP invoice is assigned to a profit center for P&L reporting. Adding profit_center_id normalizes this ',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: AP invoices for security incident costs (medical services, law enforcement overtime, property repair, legal fees, third-party security contractors) must be linked to the triggering incident for insura',
    `approval_status` STRING COMMENT 'Current status of the invoice in the AP approval workflow. Tracks whether the invoice has been reviewed and authorized by the appropriate cost center owner or finance controller per SOX segregation of duties requirements.. Valid values are `PENDING|APPROVED|REJECTED|ESCALATED`',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the invoice was approved for payment in the AP workflow. Supports SLA monitoring for invoice processing cycle time and SOX audit trail.',
    `baseline_date` DATE COMMENT 'The reference date from which payment terms are calculated in SAP FI-AP. May differ from invoice date or receipt date depending on payment terms configuration.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the AP invoice record was first created in SAP FI-AP. Serves as the audit trail anchor for SOX compliance and data lineage in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code of the invoice. Sports Entertainment operates globally (USD, EUR, GBP, AUD, CAD, JPY, etc.) requiring multi-currency AP processing.. Valid values are `^[A-Z]{3}$`',
    `discount_amount` DECIMAL(18,2) COMMENT 'The cash discount amount available if payment is made within the early payment discount period as defined in the payment terms. Used for working capital optimization and DPO management.',
    `due_date` DATE COMMENT 'The calculated date by which payment must be made to the vendor based on payment terms. Used for cash flow forecasting, DPO (Days Payable Outstanding) reporting, and payment run scheduling.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'The exchange rate applied to convert the invoice currency to the company code local currency at the time of posting. Sourced from SAP FI exchange rate tables.',
    `expense_category` STRING COMMENT 'Financial classification of the invoice as capital expenditure (CAPEX), operating expenditure (OPEX), prepaid expense, accrual, or intercompany charge. Drives balance sheet vs. P&L treatment and EBITDA impact.. Valid values are `CAPEX|OPEX|PREPAID|ACCRUAL|INTERCOMPANY`',
    `goods_receipt_number` STRING COMMENT 'The SAP material document number for the goods receipt or service entry sheet that confirms delivery of goods/services from the vendor. Required for three-way match and accrual reversal.',
    `gross_amount` DECIMAL(18,2) COMMENT 'The total gross amount of the invoice before deduction of discounts or credits, as stated on the vendor document. Expressed in the invoice currency.',
    `internal_order_number` STRING COMMENT 'SAP CO internal order number for project-based or event-specific cost tracking (e.g., a specific concert, championship event, or venue renovation). Enables event-level P&L and ROI analysis.',
    `invoice_date` DATE COMMENT 'The date printed on the vendors invoice document. Used as the baseline for payment terms calculation and aging analysis.',
    `invoice_status` STRING COMMENT 'Current workflow status of the invoice in the AP processing lifecycle. [ENUM-REF-CANDIDATE: RECEIVED|UNDER_REVIEW|APPROVED|POSTED|SCHEDULED|PAID|BLOCKED|CANCELLED — promote to reference product]',
    `invoice_type` STRING COMMENT 'Classification of the invoice document type. STANDARD: regular vendor invoice; CREDIT_MEMO: vendor credit note; DEBIT_MEMO: debit adjustment; RECURRING: periodic service invoice; PREPAYMENT: advance payment request; INTERCOMPANY: intra-group settlement.. Valid values are `STANDARD|CREDIT_MEMO|DEBIT_MEMO|RECURRING|PREPAYMENT|INTERCOMPANY`',
    `is_recurring` BOOLEAN COMMENT 'Indicates whether this invoice is part of a recurring payment schedule (e.g., monthly venue lease, broadcast rights licensing fees, HVAC maintenance contracts). Supports automated accrual and cash flow forecasting.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the AP invoice record in SAP FI-AP or the Silver Layer. Required for incremental data pipeline processing and SOX change audit trail.',
    `local_currency_amount` DECIMAL(18,2) COMMENT 'The net invoice amount translated to the company codes local (functional) currency using the exchange rate at posting date. Required for consolidated financial reporting and EBITDA calculation.',
    `net_amount` DECIMAL(18,2) COMMENT 'The net payable amount after deducting applicable discounts and credits from the gross amount. This is the amount that will be disbursed to the vendor upon payment.',
    `payment_block_reason` STRING COMMENT 'Reason code explaining why the invoice payment has been blocked in SAP FI-AP. [ENUM-REF-CANDIDATE: MANUAL_HOLD|PRICE_VARIANCE|QUANTITY_VARIANCE|DUPLICATE|MISSING_PO|PENDING_APPROVAL|DISPUTE|NONE — promote to reference product]',
    `payment_date` DATE COMMENT 'The actual date on which payment was disbursed to the vendor. Used for DPO (Days Payable Outstanding) calculation, cash flow reporting, and vendor relationship management.',
    `payment_document_number` STRING COMMENT 'SAP FI document number of the outgoing payment that cleared this invoice. Used for bank reconciliation, audit trail, and dispute resolution with vendors.',
    `payment_method` STRING COMMENT 'The method by which the invoice will be settled. ACH: Automated Clearing House; WIRE: international wire transfer; CHECK: paper check; CARD: corporate purchasing card; EFT: electronic funds transfer; INTERCOMPANY: internal settlement.. Valid values are `ACH|WIRE|CHECK|CARD|EFT|INTERCOMPANY`',
    `payment_status` STRING COMMENT 'Indicates whether the invoice has been fully paid, partially paid, cleared, or voided in SAP FI-AP. Distinct from invoice_status which tracks the approval workflow.. Valid values are `OPEN|PARTIAL|CLEARED|VOIDED`',
    `payment_terms_code` STRING COMMENT 'SAP payment terms key (e.g., NT30, 2/10NET30) defining the payment due date calculation, early payment discount percentage, and discount period. Drives cash flow forecasting and working capital management.',
    `posting_date` DATE COMMENT 'The date the invoice was posted to the general ledger in SAP FI. Determines the accounting period for revenue recognition and expense allocation.',
    `receipt_date` DATE COMMENT 'The date the invoice was physically or electronically received by the accounts payable department. Determines the start of the payment terms clock and early payment discount eligibility.',
    `sap_document_number` STRING COMMENT 'The 10-digit SAP FI document number assigned upon posting of the invoice in SAP S/4HANA. Serves as the system-of-record identifier for audit trail and journal entry cross-reference.. Valid values are `^[0-9]{10}$`',
    `tax_amount` DECIMAL(18,2) COMMENT 'The total tax amount (VAT, GST, sales tax) included in the invoice. Supports tax compliance reporting and reclaim processes across jurisdictions.',
    `three_way_match_status` STRING COMMENT 'Result of the three-way match validation between the Purchase Order (PO), Goods Receipt (GR), and Invoice Receipt (IR) in SAP MM-IV. MATCHED: all three documents align within tolerance; PARTIAL_MATCH: partial quantity or price variance; UNMATCHED: significant discrepancy; NOT_APPLICABLE: non-PO invoice.. Valid values are `MATCHED|PARTIAL_MATCH|UNMATCHED|EXCEPTION|NOT_APPLICABLE`',
    `vendor_category` STRING COMMENT 'Business classification of the vendor type for spend analytics and category management. [ENUM-REF-CANDIDATE: VENUE_SERVICES|BROADCAST_EQUIPMENT|ATHLETE_AGENT|MERCHANDISE_MFG|MEDIA_RIGHTS|CONTENT_PRODUCTION|FACILITY_MGMT|TECHNOLOGY|PROFESSIONAL_SERVICES|OTHER — promote to reference product]',
    `vendor_invoice_number` STRING COMMENT 'The invoice number as printed on the vendors source document. Used for three-way match reconciliation and vendor dispute resolution. Must be unique per vendor account.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'Amount of withholding tax deducted from the invoice payment, applicable for athlete agent fees, NIL agreement payments, and international vendor payments subject to withholding obligations.',
    CONSTRAINT pk_ap_invoice PRIMARY KEY(`ap_invoice_id`)
) COMMENT 'Accounts payable invoice received from vendors and suppliers — venue service contractors, broadcast equipment providers, athlete agents, merchandise manufacturers. Stores vendor invoice number, receipt date, posting date, vendor account, payment terms, gross amount, tax amount, net amount, currency, three-way match status (PO/GR/IR), and payment block reason. Managed in SAP FI-AP.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`payment` (
    `payment_id` BIGINT COMMENT 'Unique surrogate identifier for each payment transaction record in the Sports Entertainment finance domain. Primary key for the payment data product in the Databricks Silver Layer.',
    `agent_id` BIGINT COMMENT 'Foreign key linking to athlete.agent. Business justification: Payment records for agent commission disbursements must reference the agent being paid. Enables agent payment history tracking, commission reconciliation, and tax withholding compliance (1099/W-9) — a',
    `ap_invoice_id` BIGINT COMMENT 'Reference to the primary invoice (AR or AP) that this payment clears or partially clears. Links inbound customer receipts to AR invoices and outbound vendor disbursements to AP invoices for cash application and reconciliation.',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: The payment table handles both AP payments (invoice_id → ap_invoice already exists) and AR receipts (customer payments against AR invoices). Adding ar_invoice_id FK enables proper linkage of incoming ',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Payments are executed within a specific legal entity (company code). The company_code string field should be replaced with a typed FK to company_code.company_code_id.',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP CO cost center to which this payment is allocated for internal management accounting and EBITDA reporting. Supports expense allocation across event operations, venue management, broadcast, and athlete management divisions.',
    `fan_profile_id` BIGINT COMMENT 'Reference to the customer master record for inbound AR receipts. Identifies the payer for ticket sales, sponsorship receipts, merchandise revenue, and broadcast rights settlements. Null for outbound vendor disbursements.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Payments are posted to fiscal periods for cash accounting and reconciliation. Normalizes fiscal_year and fiscal_period INT columns.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Payments post to specific GL accounts (bank clearing accounts, cash accounts). The gl_account_code string field should be replaced with a typed FK to gl_account.gl_account_id.',
    `membership_id` BIGINT COMMENT 'Foreign key linking to fan.membership. Business justification: Membership fee payments (season tickets, VIP, fan club dues) must be reconciled against the specific membership record. Finance payment processing requires this link for cash application, auto-renewal',
    `payment_run_id` BIGINT COMMENT 'Identifier for the SAP FI automatic payment program run (F110) that generated this payment. Groups all payments executed in a single batch payment run for reconciliation and audit. Null for manually posted payments.',
    `profit_center_id` BIGINT COMMENT 'FK to finance.profit_center',
    `ticket_payment_id` BIGINT COMMENT 'Foreign key linking to ticketing.ticket_payment. Business justification: finance.payment (ERP payment record) must be reconciled with ticketing.ticket_payment (payment processor record) for cash reconciliation and period-end close. Linking these enables automated three-way',
    `ach_trace_number` STRING COMMENT 'The NACHA ACH trace number assigned to this payment entry for ACH transactions. Used for ACH return processing, NOC (Notification of Change) handling, and bank reconciliation. Null for non-ACH payment methods.',
    `bank_key` STRING COMMENT 'The SAP FI house bank key (HBKID) identifying the financial institution through which this payment is routed. Used for bank reconciliation, liquidity planning, and treasury management reporting.',
    `block_indicator` STRING COMMENT 'SAP FI payment block code (ZLSPR) indicating whether the payment is blocked from processing and the reason (e.g., manual block, dispute, audit hold, compliance review). Blank/null indicates no block. Critical for AP payment control and SOX compliance.',
    `business_area` STRING COMMENT 'The SAP FI business area (GSBER) representing the organizational segment (e.g., ticketing, broadcast, sponsorship, merchandise, venue) for cross-company-code financial reporting and internal balance sheet preparation.',
    `check_number` STRING COMMENT 'The physical or electronic check number assigned to this payment when payment_method is check. Used for check register management, positive pay file submission to banks, and stop-payment processing. Null for non-check payment methods.',
    `clearing_document_number` STRING COMMENT 'The SAP FI clearing document number (AUGBL) generated when this payment clears one or more open items in the AR or AP subledger. Used for cash application matching and open item management in the general ledger.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this payment record was first created in the SAP FI system or ingested into the Databricks Silver Layer. Provides the audit trail creation point required for SOX Section 404 internal controls and GDPR data lineage.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the transaction currency in which the payment is denominated (e.g., USD, EUR, GBP, JPY). Essential for multi-currency operations across global sports markets. Part of the MONETARY_TRIPLET.. Valid values are `^[A-Z]{3}$`',
    `direction` STRING COMMENT 'Indicates whether the payment is an outbound disbursement (AP vendor payment) or an inbound receipt (AR customer collection). Fundamental discriminator for cash flow classification and treasury reporting under IAS 7.. Valid values are `outbound|inbound`',
    `discount_amount` DECIMAL(18,2) COMMENT 'The cash discount amount deducted from the gross payment when early payment terms are honored (e.g., 2/10 net 30). Corresponds to BSEG.SKFBT in SAP FI. Used for discount capture analytics and vendor relationship management.',
    `document_date` DATE COMMENT 'The date on the original payment instrument (check date, wire instruction date, or bank statement date). Corresponds to BLDAT in SAP BKPF. Used for instrument-level audit and bank reconciliation.',
    `document_number` STRING COMMENT 'The externally-known SAP FI payment document number assigned at the time of posting. Serves as the primary business identifier for the payment transaction used in reconciliation, audit trails, and SOX financial controls. Corresponds to BELNR in SAP BKPF.',
    `due_date` DATE COMMENT 'The contractual due date by which the payment obligation must be settled per invoice payment terms. Used for early payment discount eligibility, late payment penalty calculation, and days-payable-outstanding (DPO) / days-sales-outstanding (DSO) analytics.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'The foreign currency exchange rate applied to convert the transaction currency amount to the company code local currency (typically USD) at the time of payment posting. Sourced from SAP FI exchange rate tables (TCURR). Critical for multi-currency reconciliation and FX gain/loss reporting.',
    `gross_amount` DECIMAL(18,2) COMMENT 'The total gross amount of the payment before any deductions, discounts, or withholding taxes. Expressed in the transaction currency. Forms the basis for EBITDA reporting and revenue recognition in SAP FI. Part of the MONETARY_TRIPLET for this transaction.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this payment record, including status changes, reversals, or data corrections. Required for SOX audit trail, change data capture (CDC) in the Databricks lakehouse pipeline, and GDPR accountability.',
    `local_currency_amount` DECIMAL(18,2) COMMENT 'The payment amount converted to the company code local currency (USD) using the exchange_rate at posting date. Used for consolidated financial reporting, SEC filings, and EBITDA calculations in the functional currency.',
    `net_amount` DECIMAL(18,2) COMMENT 'The net amount actually transferred after deducting cash discounts and withholding taxes from the gross amount (gross_amount - discount_amount - withholding_tax_amount). Represents the actual cash movement for treasury and bank reconciliation. Part of the MONETARY_TRIPLET.',
    `payment_date` DATE COMMENT 'The principal business event date on which the payment was executed or value-dated by the bank. Used for cash flow reporting, aging analysis, and period-end close. Corresponds to ZFBDT (baseline date) or VALUT (value date) in SAP FI. Distinct from the document posting date.',
    `payment_method` STRING COMMENT 'The financial instrument or mechanism used to execute the payment. ACH = Automated Clearing House electronic transfer; wire = bank wire transfer (SWIFT/SEPA); check = paper or electronic check; card = credit/debit card (PCI-DSS governed); digital_wallet = PayPal, Apple Pay, or similar; direct_debit = pre-authorized bank debit. Drives bank file format selection in SAP F110.. Valid values are `ACH|wire|check|card|digital_wallet|direct_debit`',
    `payment_status` STRING COMMENT 'Current lifecycle state of the payment transaction within the SAP FI workflow. initiated = payment instruction created; posted = document posted to general ledger; cleared = open items cleared; reversed = payment reversed with reversal document; failed = bank rejection or processing error; on_hold = payment blocked pending approval or dispute resolution.. Valid values are `initiated|posted|cleared|reversed|failed|on_hold`',
    `payment_type` STRING COMMENT 'Business classification of the payment transaction purpose. vendor_disbursement = AP payment to supplier/contractor; customer_receipt = AR collection from ticket buyer, sponsor, or broadcaster; intercompany_settlement = payment between Sports Entertainment legal entities; payroll_disbursement = athlete or staff salary payment; tax_payment = remittance to tax authority; refund = return of funds to customer. [ENUM-REF-CANDIDATE: vendor_disbursement|customer_receipt|intercompany_settlement|payroll_disbursement|tax_payment|refund — promote to reference product]. Valid values are `vendor_disbursement|customer_receipt|intercompany_settlement|payroll_disbursement|tax_payment|refund`',
    `posting_date` DATE COMMENT 'The accounting period posting date on which the payment document was recorded in the SAP FI general ledger. Determines the fiscal period for revenue recognition and financial reporting. May differ from payment_date for cross-period transactions.',
    `reference` STRING COMMENT 'Free-form reference text transmitted with the payment to the beneficiary bank (e.g., invoice number, contract reference, event name). Appears on bank statements and remittance advice. Corresponds to BVTYP/XBLNR in SAP FI. Critical for counterparty cash application.',
    `remittance_advice_sent` BOOLEAN COMMENT 'Indicates whether a remittance advice notification has been sent to the payee or payer detailing the invoices cleared by this payment. Supports vendor and customer communication workflows in SAP FI output management.',
    `reversal_document_number` STRING COMMENT 'The SAP FI document number of the reversal posting if this payment has been reversed (e.g., returned ACH, stopped check, duplicate payment correction). Null if the payment has not been reversed. Links to the reversing document for audit trail.',
    `reversal_reason_code` STRING COMMENT 'SAP FI reversal reason code (STGRD) explaining why the payment was reversed (e.g., wrong amount, duplicate, bank return, stop payment). Null if not reversed. Used for exception reporting and fraud detection analytics.',
    `special_gl_indicator` STRING COMMENT 'SAP FI special GL indicator (UMSKZ) classifying non-standard postings such as down payments, guarantees, or security deposits associated with this payment. Blank for standard payment postings. Used for balance sheet sub-classification.',
    `swift_reference` STRING COMMENT 'The SWIFT end-to-end transaction reference (UETR or TRN) for wire transfer payments. Enables real-time payment tracking via SWIFT gpi and bank confirmation matching. Null for non-wire payment methods.',
    `terms_code` STRING COMMENT 'The SAP FI payment terms key (ZTERM) governing the due date calculation and early payment discount conditions for this transaction (e.g., NT30, 2/10NET30). Inherited from the invoice or vendor/customer master. Drives DSO and DPO analytics.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'The amount of withholding tax deducted from the payment at source, applicable to athlete NIL payments, foreign vendor disbursements, and royalty settlements. Reported to tax authorities and reflected in SAP FI withholding tax tables (WITH_ITEM).',
    CONSTRAINT pk_payment PRIMARY KEY(`payment_id`)
) COMMENT 'Financial payment transaction recording the settlement of accounts receivable and accounts payable obligations. Captures payment document number, payment date, payment method (ACH, wire, check, card, digital wallet), bank account, cleared invoice references, payment amount, currency, exchange rate, clearing document number, and payment run ID. Covers outbound vendor disbursements, inbound customer receipts, and automated payment program runs in SAP FI. Links to AR invoices (customer receipts) and AP invoices (vendor payments) for complete cash application and reconciliation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`fixed_asset` (
    `fixed_asset_id` BIGINT COMMENT 'Unique surrogate identifier for the fixed asset master record in the SAP FI-AA module. Primary key for the Silver Layer lakehouse table.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Fixed assets are owned by a specific legal entity (company code) in SAP FI-AA. The company_code string field should be replaced with a typed FK to company_code.company_code_id.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Fixed assets in SAP FI-AA are assigned to cost centers for depreciation allocation and cost reporting. The cost_center_code string field should be replaced with a typed FK to cost_center.cost_center_i',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Fixed assets post to specific GL accounts (asset acquisition accounts, accumulated depreciation accounts). The gl_account_code string field should be replaced with a typed FK to gl_account.gl_account_',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Fixed assets are attributed to profit centers for segment-level asset reporting and EBITDA calculation. The profit_center_code string field should be replaced with a typed FK to profit_center.profit_c',
    `accumulated_depreciation` DECIMAL(18,2) COMMENT 'Total depreciation charged against the asset from the in-service date to the current reporting period. Contra-asset balance used to calculate net book value. Sourced from SAP FI-AA depreciation simulation/posting runs.',
    `acquisition_cost` DECIMAL(18,2) COMMENT 'Original historical cost of the fixed asset at the time of acquisition or capitalization, in the company code currency. Includes purchase price, import duties, and directly attributable costs to bring the asset to its intended use. CAPEX SSOT figure.',
    `acquisition_date` DATE COMMENT 'Date on which the fixed asset was acquired, purchased, or constructed and capitalized. Used as the start date for depreciation calculation and CAPEX reporting. Corresponds to SAP FI-AA Capitalization Date.',
    `annual_depreciation_charge` DECIMAL(18,2) COMMENT 'Planned annual depreciation expense for the current fiscal year as calculated by SAP FI-AA. Used in FP&A budgeting, EBITDA bridge analysis, and Workday Adaptive Planning depreciation forecasts.',
    `asset_category` STRING COMMENT 'High-level classification distinguishing tangible assets (stadium structures, OB trucks, scoreboards), intangible assets (broadcast rights, software licenses, NIL-related IP), right-of-use assets (IFRS 16 leases), and investment property. Drives balance sheet line-item presentation.. Valid values are `tangible|intangible|right_of_use|investment_property`',
    `asset_class_code` STRING COMMENT 'SAP FI-AA asset class code that determines the depreciation area, useful life defaults, and GL account determination (e.g., 1000 for Buildings, 2000 for Machinery, 3000 for Intangible Assets, 4000 for Broadcast Rights). Drives CAPEX categorization and balance sheet classification.',
    `asset_class_name` STRING COMMENT 'Human-readable name of the SAP asset class (e.g., Stadium Structures, Broadcast Equipment, OB Trucks, Digital Platform Infrastructure, Acquired Broadcast Rights, Scoreboards & LED Systems). Used in financial reporting and CAPEX dashboards.',
    `asset_description` STRING COMMENT 'Short descriptive name of the fixed asset as recorded in SAP FI-AA (e.g., OB Truck Unit 7, Broadcast Tower – East Campus, Stadium Roof Structure – Section A). Used on depreciation schedules and financial statements.',
    `asset_location_code` STRING COMMENT 'Physical or logical location code where the asset is deployed (e.g., venue code, broadcast facility code, data center identifier). Supports asset tracking, insurance valuation, and ADA/OSHA compliance reporting for venue assets.',
    `asset_location_description` STRING COMMENT 'Human-readable description of the assets physical location (e.g., Main Stadium – East Stand, Broadcast Tower – Roof Level 3, OB Truck Depot – Training Facility). Used in physical asset verification and insurance schedules.',
    `asset_number` STRING COMMENT 'Externally-known SAP FI-AA asset number (main asset number) assigned at capitalization. Used as the primary business identifier on CAPEX reports, depreciation schedules, and audit trails. Format follows SAP company-code-prefixed numbering convention.',
    `asset_status` STRING COMMENT 'Current lifecycle state of the fixed asset. under_construction = Assets Under Construction (AUC) not yet capitalized; in_service = actively depreciated; idle = temporarily out of service; impaired = impairment loss recognized; disposed = sold, scrapped, or retired; transferred = intercompany or intra-company transfer in progress.. Valid values are `under_construction|in_service|idle|impaired|disposed|transferred`',
    `asset_subnumber` STRING COMMENT 'SAP FI-AA sub-number identifying a component or addition to the main asset (e.g., a scoreboard upgrade added to the main stadium structure asset). Enables component-level depreciation tracking.',
    `broadcast_rights_expiry_date` DATE COMMENT 'For intangible assets representing acquired broadcast rights (e.g., RSN rights, OTT streaming rights, PPV event rights), the contractual expiry date of the rights. Drives amortization end date and rights renewal planning. Null for tangible assets.',
    `capex_budget_code` STRING COMMENT 'Reference to the approved CAPEX budget line item or investment program code in Workday Adaptive Planning / SAP IM (Investment Management) that authorized the acquisition of this asset. Supports CAPEX vs. budget variance reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the fixed asset master record was first created in SAP FI-AA. Provides the audit trail creation event required for SOX internal controls and data lineage in the Silver Layer lakehouse.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this asset record (e.g., USD, GBP, EUR). Supports multi-currency reporting for global sports entertainment operations.. Valid values are `^[A-Z]{3}$`',
    `depreciation_area_code` STRING COMMENT 'SAP FI-AA depreciation area identifier representing the valuation basis (e.g., 01 for book depreciation per local GAAP, 15 for tax depreciation, 30 for IFRS). Enables parallel valuation for SEC reporting and tax compliance.',
    `depreciation_method_code` STRING COMMENT 'SAP FI-AA depreciation key/method code defining the calculation method (e.g., LINR for straight-line, DG30 for declining balance 30%, MANU for manual, UNIT for units-of-production). Determines how accumulated depreciation is calculated each period.',
    `disposal_date` DATE COMMENT 'Date on which the asset was retired, sold, scrapped, or otherwise disposed of. Triggers the derecognition of the asset from the balance sheet and recognition of any gain or loss on disposal in SAP FI-AA.',
    `disposal_proceeds` DECIMAL(18,2) COMMENT 'Net proceeds received upon disposal or sale of the asset. Used to calculate the gain or loss on disposal recognized in the income statement. Relevant for stadium asset sales, OB truck fleet disposals, and broadcast rights expirations.',
    `disposal_type` STRING COMMENT 'Method by which the asset was disposed of. sale = sold to third party; scrap = physically scrapped; transfer = intercompany or intra-company transfer; donation = donated; write_off = written off; insurance_claim = disposed via insurance settlement (e.g., storm-damaged broadcast tower).. Valid values are `sale|scrap|transfer|donation|write_off|insurance_claim`',
    `impairment_loss` DECIMAL(18,2) COMMENT 'Cumulative impairment loss recognized on the asset where the carrying amount exceeds the recoverable amount (per IAS 36 / ASC 360). Reduces net book value. Relevant for broadcast rights, goodwill-adjacent intangibles, and underperforming venue assets.',
    `in_service_date` DATE COMMENT 'Date the asset was placed into active service and depreciation commenced. May differ from acquisition_date for assets under construction. Drives the depreciation start period in SAP FI-AA.',
    `insurance_policy_number` STRING COMMENT 'Reference number of the insurance policy covering this asset against loss, damage, or liability. Critical for venue assets (stadium structures), broadcast infrastructure (OB trucks, towers), and high-value equipment. Supports risk management and claims processing.',
    `insured_value` DECIMAL(18,2) COMMENT 'Declared insured replacement value of the asset as agreed with the insurer. May differ from net book value (NBV) for high-value venue and broadcast infrastructure assets. Used for insurance adequacy reviews.',
    `is_fully_depreciated` BOOLEAN COMMENT 'Indicates whether the asset has been fully depreciated (net book value equals residual value). Fully depreciated assets still in service are flagged for management review and potential useful life extension assessment per IAS 16.',
    `is_leased` BOOLEAN COMMENT 'Indicates whether the asset is a right-of-use (ROU) asset recognized under IFRS 16 / ASC 842 (e.g., leased venue, leased OB truck, leased broadcast satellite capacity). Drives separate balance sheet presentation and lease liability linkage.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent change to the fixed asset master record in SAP FI-AA. Used for incremental data loading, change detection in the Silver Layer, and SOX audit trail completeness.',
    `last_physical_verification_date` DATE COMMENT 'Date of the most recent physical inventory count or asset verification exercise confirming the assets existence and condition. Required for SOX internal controls and annual audit procedures.',
    `net_book_value` DECIMAL(18,2) COMMENT 'Current carrying amount of the fixed asset: acquisition_cost plus subsequent_acquisition_cost minus accumulated_depreciation minus impairment_loss. Reported on the balance sheet. Refreshed each period-end close from SAP FI-AA.',
    `purchase_order_number` STRING COMMENT 'SAP MM purchase order number associated with the acquisition of the asset. Provides the procurement-to-capitalization audit trail required for SOX compliance and CAPEX authorization controls.',
    `residual_value` DECIMAL(18,2) COMMENT 'Estimated amount the entity expects to recover from the asset at the end of its useful life (salvage value). Deducted from acquisition cost to determine the depreciable base. Reviewed annually per IAS 16.',
    `revaluation_amount` DECIMAL(18,2) COMMENT 'Cumulative upward or downward revaluation adjustment to the assets carrying amount under the IAS 16 revaluation model (where adopted). Recorded in the revaluation surplus in equity. Applicable to stadium land and property assets.',
    `serial_number` STRING COMMENT 'Manufacturers serial number or unique physical identifier for the asset (e.g., OB truck chassis number, scoreboard controller serial, broadcast transmitter serial). Used for physical verification, warranty claims, and insurance schedules.',
    `subsequent_acquisition_cost` DECIMAL(18,2) COMMENT 'Cumulative cost of subsequent capital additions or improvements to the asset (e.g., stadium seat upgrades, scoreboard technology refresh, broadcast tower antenna replacement). Added to the assets gross book value.',
    `useful_life_periods` STRING COMMENT 'Estimated useful life expressed in fiscal periods (months) for assets with sub-annual depreciation granularity. Used in SAP FI-AA period-based depreciation calculations alongside useful_life_years.',
    `useful_life_years` STRING COMMENT 'Estimated useful economic life of the asset in years, as determined at capitalization and used to calculate straight-line or other depreciation. Reviewed annually per IAS 16 (e.g., 40 years for stadium structures, 5 years for OB trucks, 3 years for broadcast rights).',
    `wbs_element` STRING COMMENT 'SAP PS Work Breakdown Structure element linked to the asset, used for CAPEX project tracking during the Assets Under Construction (AUC) phase (e.g., stadium renovation project, broadcast tower installation). Populated until the AUC is settled to a final asset.',
    CONSTRAINT pk_fixed_asset PRIMARY KEY(`fixed_asset_id`)
) COMMENT 'Fixed asset master record in SAP FI-AA representing capitalized physical and intangible assets — stadium structures, broadcast towers, OB trucks, scoreboards, digital platform infrastructure, and acquired broadcast rights. Stores asset class, acquisition date, acquisition cost, useful life, depreciation method, accumulated depreciation, net book value, and disposal status. SSOT for CAPEX and depreciation accounting.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`revenue_recognition_schedule` (
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for each revenue recognition schedule record within the finance domain. Primary key for the revenue_recognition_schedule data product.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Revenue recognition schedules are scoped to a specific legal entity for SEC reporting compliance. The company_code string field should be replaced with a typed FK to company_code.company_code_id.',
    `competition_round_id` BIGINT COMMENT 'Foreign key linking to event.competition_round. Business justification: Broadcast rights contracts often specify per-round fee tranches (e.g., quarterfinal, semifinal, final). Revenue recognition schedules must reference the competition round as the performance obligation',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Revenue recognition schedules are attributed to cost centers for cost allocation and reporting. The cost_center_code string field should be replaced with a typed FK to cost_center.cost_center_id.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Revenue recognition schedules recognize revenue into specific fiscal periods. Normalizes fiscal_year and fiscal_period INT columns by linking to fiscal_period master.',
    `fixture_id` BIGINT COMMENT 'Foreign key linking to event.fixture. Business justification: Under ASC 606/IFRS 15, each fixture is a performance obligation for broadcast rights and gate revenue. Revenue recognition schedules must reference the specific fixture whose completion triggers defer',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Each recognition event generates a journal entry posting. The journal_entry_reference string field is a denormalized reference that should be replaced with a typed FK journal_entry_id → journal_entry.',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Match result confirmation is the triggering event for recognizing gate receipts, PPV, and broadcast revenue. Linking revenue_recognition_schedule to match_result enables finance to confirm performance',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Media rights deals are the primary contracts requiring ASC 606/IFRS 15 revenue recognition schedules. Finance creates recognition schedules per rights deal for deferred revenue management and period r',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: NIL agreement revenue must be recognized over the agreement term per ASC 606. The revenue_recognition_schedule must reference the nil_agreement driving the recognition schedule for proper deferred rev',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Revenue recognition schedules are attributed to profit centers for segment-level revenue reporting. The profit_center_code string field should be replaced with a typed FK to profit_center.profit_cente',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Revenue recognition schedules post recognized revenue to a specific GL account. The gl_account_code string field should be replaced with a typed FK recognized_gl_account_id → gl_account.gl_account_id.',
    `venue_assignment_id` BIGINT COMMENT 'Foreign key linking to event.venue_assignment. Business justification: Venue revenue-sharing agreements (venue_assignment.revenue_share_pct) create deferred revenue obligations recognized over the event lifecycle. Finance must link recognition schedules to the specific v',
    `accounting_standard` STRING COMMENT 'The revenue recognition accounting standard applied to this schedule. ASC_606 for US GAAP entities; IFRS_15 for international entities; ASC_606_IFRS_15 for dual-reporting entities. Determines the specific recognition criteria and disclosure requirements.. Valid values are `ASC_606|IFRS_15|ASC_606_IFRS_15`',
    `constraint_applied_flag` BOOLEAN COMMENT 'Indicates whether the variable consideration constraint has been applied to limit the recognized amount to the extent it is highly probable (IFRS 15) or probable (ASC 606) that a significant revenue reversal will not occur. Required for ASC 606 / IFRS 15 compliance documentation.',
    `contract_effective_date` DATE COMMENT 'The date the underlying contract became legally binding and enforceable. Used as the ASC 606 contract inception date for determining transaction price and allocating to performance obligations.',
    `contract_expiry_date` DATE COMMENT 'The date the underlying contract expires or terminates. For multi-year broadcast rights or naming rights agreements, this may be several years in the future. Nullable for evergreen contracts.',
    `contract_type` STRING COMMENT 'Classification of the underlying revenue contract driving this recognition schedule. Determines applicable recognition methodology and disclosure requirements. [ENUM-REF-CANDIDATE: broadcast_rights|sponsorship|naming_rights|season_ticket|multi_event|licensing|merchandise|ppv|ott_subscription|nil_agreement — promote to reference product]. Valid values are `broadcast_rights|sponsorship|naming_rights|season_ticket|multi_event|licensing`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this revenue recognition schedule record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides the audit trail creation point required for SOX compliance and data lineage in the Databricks Silver Layer.',
    `cumulative_recognized_amount` DECIMAL(18,2) COMMENT 'Total revenue recognized to date against this performance obligation since the recognition start date. Equals total_contract_value minus deferred_revenue_balance at any point in time. Used for period-end reconciliation and ASC 606 cumulative catch-up adjustment calculations.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts on this recognition schedule (e.g., USD, EUR, GBP). Required for multi-currency broadcast rights and international sponsorship contracts.. Valid values are `^[A-Z]{3}$`',
    `current_period_recognition_amount` DECIMAL(18,2) COMMENT 'Revenue amount to be recognized in the current accounting period for this performance obligation. Drives the period-end journal entry generation in SAP S/4HANA FI/CO. For straight-line method, equals total_contract_value divided by total periods; for milestone/event-based, equals the value of the milestone achieved.',
    `deferred_revenue_balance` DECIMAL(18,2) COMMENT 'Current outstanding deferred revenue balance for this performance obligation — the portion of total contract value received or billed but not yet recognized as earned revenue. Drives the deferred revenue waterfall report and balance sheet liability disclosure. Updated each period-end close in SAP S/4HANA FI.',
    `deferred_revenue_gl_account_code` STRING COMMENT 'SAP S/4HANA GL account code for the deferred revenue liability balance sheet account. The deferred revenue balance is carried here until recognized. Required for balance sheet reporting and SOX-compliant financial controls.. Valid values are `^[0-9]{6,10}$`',
    `discount_rate` DECIMAL(18,2) COMMENT 'The discount rate (as a decimal, e.g., 0.0450 for 4.50%) used to adjust for the significant financing component in the transaction price. Reflects the rate that would be used in a separate financing transaction between the entity and the counterparty at contract inception. Null when significant_financing_flag is false.',
    `last_recognition_date` DATE COMMENT 'The date of the most recent revenue recognition posting for this performance obligation. Used to confirm period-end close completion and to identify schedules that have not been processed in the current period.',
    `modification_date` DATE COMMENT 'The effective date of the most recent contract modification affecting this recognition schedule. Null when modification_flag is false. Used to determine the prospective or cumulative catch-up adjustment period.',
    `modification_flag` BOOLEAN COMMENT 'Indicates whether this recognition schedule reflects a contract modification (e.g., renegotiated broadcast rights fee, amended sponsorship scope). When true, the modification accounting treatment (prospective or cumulative catch-up) per ASC 606-10-25-12 / IFRS 15.18 must be documented.',
    `next_recognition_date` DATE COMMENT 'The scheduled date for the next revenue recognition posting. Used by the FP&A team in Workday Adaptive Planning for revenue forecasting and by the accounting team to manage period-end close calendars.',
    `performance_obligation_description` STRING COMMENT 'Narrative description of the distinct performance obligation being recognized, as documented in the contract and required for ASC 606 / IFRS 15 disclosure. Examples: Exclusive broadcast rights for NFL regular season games FY2024-FY2026, Naming rights for stadium facade and digital signage, Season ticket package — 41 home games.',
    `periods_recognized` STRING COMMENT 'Number of accounting periods for which revenue has been recognized to date against this performance obligation. Used to track progress toward full recognition and to validate cumulative_recognized_amount in period-end reconciliation.',
    `recognition_basis` STRING COMMENT 'Indicates whether revenue is recognized over time (e.g., broadcast rights delivered continuously over a season) or at a point in time (e.g., a one-time PPV event, a single concert). Fundamental ASC 606 / IFRS 15 classification that determines the recognition pattern.. Valid values are `over_time|point_in_time`',
    `recognition_end_date` DATE COMMENT 'The date on which revenue recognition is expected to be fully completed for this performance obligation. For multi-year broadcast rights, this may span several fiscal years. Nullable for open-ended or usage-based obligations without a fixed end date.',
    `recognition_method` STRING COMMENT 'The accounting method used to recognize revenue over the performance obligation period. Straight-line = equal amounts per period; Milestone = upon achievement of defined deliverables; Usage-based = proportional to actual consumption (e.g., broadcast impressions, CPM); Event-based = upon occurrence of specific events (e.g., game played); Proportional performance = based on percentage of obligation fulfilled.. Valid values are `straight_line|milestone|usage_based|event_based|proportional_performance`',
    `recognition_start_date` DATE COMMENT 'The date on which revenue recognition commences for this performance obligation. Typically aligns with contract effective date or the date the entity begins satisfying the performance obligation (e.g., first broadcast date, season opener, naming rights activation).',
    `recognition_status` STRING COMMENT 'Current lifecycle state of the revenue recognition schedule. Draft = under review; Active = currently recognizing revenue; Suspended = temporarily halted (e.g., contract dispute); Completed = fully recognized; Cancelled = contract terminated before full recognition.. Valid values are `draft|active|suspended|completed|cancelled`',
    `schedule_number` STRING COMMENT 'Externally-visible business identifier for this recognition schedule, formatted as RRS-{YYYY}-{NNNNNN}. Used in SAP S/4HANA FI/CO journal entry references, audit workpapers, and SEC financial reporting disclosures.. Valid values are `^RRS-[0-9]{4}-[0-9]{6}$`',
    `significant_financing_flag` BOOLEAN COMMENT 'Indicates whether the contract contains a significant financing component requiring adjustment of the transaction price for the time value of money per ASC 606-10-32-15 / IFRS 15.60. Common in multi-year prepaid broadcast rights deals where cash is received significantly in advance of performance.',
    `total_contract_value` DECIMAL(18,2) COMMENT 'The total transaction price allocated to this performance obligation as determined at contract inception per ASC 606 Step 3 (Determine Transaction Price) and Step 4 (Allocate Transaction Price). Expressed in the contract currency. Used as the basis for deferred revenue waterfall reporting.',
    `total_recognition_periods` STRING COMMENT 'Total number of accounting periods over which revenue is to be recognized for this performance obligation. Used for straight-line recognition calculations and deferred revenue waterfall projections. For event-based recognition, represents the total number of qualifying events.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this revenue recognition schedule record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Required for change data capture in the Databricks Silver Layer and SOX audit trail completeness.',
    `variable_consideration_amount` DECIMAL(18,2) COMMENT 'The estimated amount of variable consideration included in the transaction price at the most likely amount or expected value method per ASC 606. Applicable for contracts with performance bonuses, ratings escalators, or PPV revenue share components. Null when variable_consideration_flag is false.',
    `variable_consideration_flag` BOOLEAN COMMENT 'Indicates whether the transaction price includes variable consideration components (e.g., performance bonuses, ratings-based escalators, PPV revenue share, usage-based royalties). When true, the constraint on variable consideration per ASC 606 Step 3 must be applied and reassessed each reporting period.',
    CONSTRAINT pk_revenue_recognition_schedule PRIMARY KEY(`revenue_recognition_schedule_id`)
) COMMENT 'Revenue recognition schedule governing when and how deferred revenue is recognized into earned revenue per ASC 606 / IFRS 15 standards. Applies to multi-year broadcast rights contracts, season ticket packages, multi-event sponsorship deals, and long-term naming rights agreements. Stores contract reference, performance obligation description, total contract value, deferred balance, recognition method (straight-line, milestone, usage-based), recognition start/end dates, period recognition amounts, and cumulative recognized amount. SSOT for ASC 606 compliance, deferred revenue waterfall reporting, and period-end revenue recognition journal entry generation. Distinct from recurring_revenue which tracks commercial ARR/churn metrics — this product owns the accounting treatment and timing of revenue recognition.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`fiscal_period` (
    `fiscal_period_id` BIGINT COMMENT 'Primary key for fiscal_period',
    `parent_fiscal_period_id` BIGINT COMMENT 'Reference to the parent fiscal period for hierarchical period structures (e.g., a monthly period rolling up to a quarterly period). Null for top-level periods.',
    `primary_prior_fiscal_period_id` BIGINT COMMENT 'Self-referencing FK on fiscal_period (prior_fiscal_period_id)',
    `budget_version` STRING COMMENT 'The budget version or scenario applicable to this fiscal period (e.g., Original Budget, Revised Budget, Forecast).',
    `calendar_month` STRING COMMENT 'The calendar month (1-12) in which this fiscal period starts, used for calendar-to-fiscal mapping.',
    `calendar_quarter` STRING COMMENT 'The calendar quarter (1-4) in which this fiscal period starts, used for calendar-to-fiscal mapping.',
    `calendar_year` STRING COMMENT 'The calendar year in which this fiscal period starts, used for calendar-to-fiscal mapping.',
    `closed_date` DATE COMMENT 'The date when this fiscal period was officially closed for transaction entry (yyyy-MM-dd). Null if not yet closed.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this fiscal period record was first created in the system (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `days_in_period` STRING COMMENT 'Total number of calendar days in this fiscal period, used for pro-rata calculations and variance analysis.',
    `end_date` DATE COMMENT 'The last calendar date included in this fiscal period (yyyy-MM-dd).',
    `fiscal_month` STRING COMMENT 'The fiscal month number within the fiscal year (1-12). Null for non-monthly periods.',
    `fiscal_period_description` STRING COMMENT 'Additional descriptive information about the fiscal period, including special characteristics or notes.',
    `fiscal_quarter` STRING COMMENT 'The fiscal quarter number within the fiscal year (1-4). Null for non-quarterly periods.',
    `fiscal_week` STRING COMMENT 'The fiscal week number within the fiscal year (1-52 or 1-53). Null for non-weekly periods.',
    `fiscal_year` STRING COMMENT 'The fiscal year to which this period belongs (e.g., 2024).',
    `is_adjustment_period` BOOLEAN COMMENT 'Indicates whether this is a special adjustment period (e.g., Period 13) used for year-end adjustments and accruals (True/False).',
    `is_current_period` BOOLEAN COMMENT 'Indicates whether this is the current active fiscal period (True/False).',
    `is_year_end_period` BOOLEAN COMMENT 'Indicates whether this period is the final period of the fiscal year, requiring year-end closing procedures (True/False).',
    `locked_date` DATE COMMENT 'The date when this fiscal period was locked for final reporting and audit (yyyy-MM-dd). Null if not yet locked.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this fiscal period record was last modified (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `period_code` STRING COMMENT 'Business identifier code for the fiscal period, typically combining fiscal year and period number (e.g., FY2024-Q1, FY2024-P01).',
    `period_name` STRING COMMENT 'Human-readable name of the fiscal period (e.g., Q1 2024, January 2024, FY2024 Period 1).',
    `period_number` STRING COMMENT 'Sequential period number within the fiscal year, used for ordering and reporting.',
    `period_status` STRING COMMENT 'Current lifecycle status of the fiscal period. Future: not yet started; Open: active for transactions; Closed: no new transactions allowed; Locked: closed and finalized for reporting; Archived: historical record only.',
    `period_type` STRING COMMENT 'Classification of the fiscal period granularity (annual, semi-annual, quarterly, monthly, weekly, or custom).',
    `reporting_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code used for financial reporting in this period (e.g., USD, EUR, GBP).',
    `sec_filing_required` BOOLEAN COMMENT 'Indicates whether this fiscal period requires SEC financial reporting filings (10-Q, 10-K) for publicly traded entities (True/False).',
    `sox_audit_required` BOOLEAN COMMENT 'Indicates whether this fiscal period requires SOX compliance audit procedures (True/False).',
    `start_date` DATE COMMENT 'The first calendar date included in this fiscal period (yyyy-MM-dd).',
    `working_days_in_period` STRING COMMENT 'Number of business working days in this fiscal period, excluding weekends and holidays, used for operational metrics.',
    CONSTRAINT pk_fiscal_period PRIMARY KEY(`fiscal_period_id`)
) COMMENT 'Master reference table for fiscal_period. Referenced by fiscal_period_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`payment_run` (
    `payment_run_id` BIGINT COMMENT 'Primary key for payment_run',
    `company_code_id` BIGINT COMMENT 'FK to finance.company_code',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: payment_run has fiscal_period (INT) and fiscal_year (INT) as raw denormalized columns but no FK to finance.fiscal_period. Payment runs are executed within specific fiscal periods for period-end close ',
    `primary_original_payment_run_id` BIGINT COMMENT 'Reference to the original payment run being reversed. Populated only when is_reversal is true. Used to maintain audit trail of corrections.',
    `approval_status` STRING COMMENT 'The approval workflow status for the payment run: pending indicates awaiting authorization, approved indicates cleared for execution, rejected indicates denied by approver, bypassed indicates no approval required per policy.',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time when the payment run was approved. Used for audit trails and compliance reporting.',
    `completion_timestamp` TIMESTAMP COMMENT 'The precise date and time when the payment run execution finished, whether successfully or with errors. Used to calculate processing duration and SLA compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the payment run record was first created in the system. Used for audit trails and data lineage.',
    `discount_amount` DECIMAL(18,2) COMMENT 'The total cash discount amount taken across all payments in this run for early payment. Represents savings achieved through prompt payment programs.',
    `error_log` STRING COMMENT 'Detailed error messages and exception logs for failed payments or processing issues. Used for troubleshooting and root cause analysis.',
    `execution_timestamp` TIMESTAMP COMMENT 'The precise date and time when the payment run execution began. Critical for audit trails and reconciliation with banking systems.',
    `failed_payment_amount` DECIMAL(18,2) COMMENT 'The sum of all failed payment amounts that were not disbursed. Represents funds that remain in the company account and require reprocessing.',
    `failed_payment_count` STRING COMMENT 'The number of payment transactions that failed during processing due to validation errors, insufficient funds, or system issues. Requires manual intervention.',
    `is_reversal` BOOLEAN COMMENT 'Boolean flag indicating whether this payment run is a reversal of a previous run. True indicates reversal, false indicates original payment run.',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when the payment run record was last modified. Used for audit trails and change tracking.',
    `notes` STRING COMMENT 'Free-text notes and comments about the payment run. Used to document special circumstances, manual interventions, or business context.',
    `payment_currency` STRING COMMENT 'ISO 4217 three-letter currency code for all payments in this run. All disbursements within a single run are typically in the same currency.',
    `payment_file_format` STRING COMMENT 'The electronic file format standard used for bank transmission: ISO 20022 for international standard, NACHA for US ACH, BAI2 for bank reporting, MT940 for SWIFT, CAMT.053 for account statements, proprietary for bank-specific formats.',
    `payment_file_name` STRING COMMENT 'The name of the electronic payment file generated for bank transmission. Used for file tracking and reconciliation with bank acknowledgments.',
    `payment_method` STRING COMMENT 'The payment instrument used for disbursements in this run: ACH for Automated Clearing House, wire for wire transfer, check for physical checks, EFT for Electronic Funds Transfer, SEPA for Single Euro Payments Area, BACS for UK Bankers Automated Clearing Services.',
    `payment_run_status` STRING COMMENT 'Current lifecycle status of the payment run: draft indicates initial creation, scheduled indicates approved and queued, processing indicates active execution, completed indicates successful finish, failed indicates execution error, cancelled indicates user-terminated run.',
    `payment_terms` STRING COMMENT 'The standard payment terms code applied to invoices included in this run. Defines due date calculation and discount eligibility.',
    `posting_date` DATE COMMENT 'The accounting date on which payment transactions are posted to the general ledger. May differ from value date for period-end processing.',
    `reconciliation_status` STRING COMMENT 'The status of bank statement reconciliation for this payment run: pending indicates awaiting bank confirmation, reconciled indicates matched with bank statement, discrepancy indicates mismatch requiring investigation, under_review indicates active reconciliation process.',
    `run_number` STRING COMMENT 'Business-facing unique identifier for the payment run, typically formatted as PR-YYYYMMDD-NNNN for external reference and audit trails.',
    `run_type` STRING COMMENT 'Classification of the payment run based on business purpose: standard for regular scheduled runs, emergency for urgent off-cycle payments, supplemental for additional payments, reversal for payment corrections, adjustment for reconciliation runs, interim for partial disbursements.',
    `scheduled_date` DATE COMMENT 'The date on which the payment run is scheduled to execute. Used for planning and cash flow forecasting.',
    `successful_payment_amount` DECIMAL(18,2) COMMENT 'The sum of all successfully processed payment amounts. Used to reconcile actual cash outflows against planned disbursements.',
    `successful_payment_count` STRING COMMENT 'The number of payment transactions that were successfully processed and transmitted to the bank. Used to calculate success rate and identify exceptions.',
    `total_payment_amount` DECIMAL(18,2) COMMENT 'The sum of all payment amounts included in this run, expressed in the payment currency. Used for cash position management and bank account reconciliation.',
    `total_payment_count` STRING COMMENT 'The total number of individual payment transactions included in this payment run. Used for reconciliation and control totals.',
    `transmission_timestamp` TIMESTAMP COMMENT 'The date and time when the payment file was transmitted to the bank. Critical for cut-off time compliance and value dating.',
    `value_date` DATE COMMENT 'The date on which funds are to be debited from the company account and credited to payee accounts. Used for cash flow forecasting and liquidity management.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'The total withholding tax amount deducted from payments in this run. Required for tax compliance and reporting to tax authorities.',
    CONSTRAINT pk_payment_run PRIMARY KEY(`payment_run_id`)
) COMMENT 'Master reference table for payment_run. Referenced by payment_run_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`finance`.`ledger` (
    `ledger_id` BIGINT COMMENT 'Primary key for ledger',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: ledger has company_code (STRING) but no FK to finance.company_code. In SAP S/4HANA, ledgers are assigned to company codes (legal entities). The leading ledger and extension ledgers are configured per ',
    `parent_ledger_id` BIGINT COMMENT 'Self-referencing FK on ledger (parent_ledger_id)',
    `accounting_principle` STRING COMMENT 'The accounting standard or principle governing this ledger (e.g., US GAAP, IFRS, local statutory requirements).',
    `approval_status` STRING COMMENT 'Current approval workflow status for this ledger configuration before it becomes operational.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when this ledger configuration was approved for operational use.',
    `audit_trail_level` STRING COMMENT 'The level of audit trail and change tracking maintained for transactions posted to this ledger.',
    `balance_carryforward_method` STRING COMMENT 'The method used to carry forward account balances from one fiscal year to the next in this ledger.',
    `closed_timestamp` TIMESTAMP COMMENT 'The date and time when this ledger was closed and no longer accepts new transactions.',
    `consolidation_ledger_flag` BOOLEAN COMMENT 'Indicates whether this ledger is used for group consolidation and intercompany elimination purposes.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this ledger record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code representing the functional currency of the ledger.',
    `effective_end_date` DATE COMMENT 'The date on which this ledger ceases to be active for new transactions. Null indicates an open-ended ledger.',
    `effective_start_date` DATE COMMENT 'The date from which this ledger becomes active and available for financial transactions.',
    `fiscal_year_variant` STRING COMMENT 'Code identifying the fiscal year calendar structure used by this ledger (e.g., calendar year, 4-4-5 retail calendar).',
    `intercompany_elimination_flag` BOOLEAN COMMENT 'Indicates whether this ledger includes intercompany elimination entries for consolidated financial reporting.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this ledger record was last updated or modified.',
    `leading_ledger_flag` BOOLEAN COMMENT 'Indicates whether this ledger is the leading (primary) ledger for the organization used for statutory reporting and external financial statements.',
    `ledger_code` STRING COMMENT 'Unique business identifier code for the ledger used in financial reporting and system integration. Externally-known identifier.',
    `ledger_description` STRING COMMENT 'Detailed business description and purpose of the ledger including its scope and intended use cases.',
    `ledger_name` STRING COMMENT 'Full descriptive name of the ledger for human-readable identification and reporting purposes.',
    `ledger_status` STRING COMMENT 'Current lifecycle status of the ledger indicating whether it is available for posting transactions.',
    `ledger_type` STRING COMMENT 'Classification of the ledger based on its accounting purpose and scope within the enterprise financial architecture.',
    `notes` STRING COMMENT 'Additional free-text notes or comments about this ledger for internal reference and documentation purposes.',
    `parallel_accounting_flag` BOOLEAN COMMENT 'Indicates whether this ledger is used for parallel accounting to support multiple accounting standards simultaneously.',
    `posting_allowed_flag` BOOLEAN COMMENT 'Indicates whether direct financial postings are currently permitted to this ledger.',
    `retained_earnings_account` STRING COMMENT 'The general ledger account number used for retained earnings and profit/loss carry-forward in this ledger.',
    `segment_reporting_enabled_flag` BOOLEAN COMMENT 'Indicates whether this ledger supports segment reporting for business unit or geographic financial analysis.',
    `sox_compliant_flag` BOOLEAN COMMENT 'Indicates whether this ledger is subject to Sarbanes-Oxley Act internal control requirements and audit trails.',
    `valuation_area` STRING COMMENT 'Code identifying the valuation area or approach used for asset and inventory valuation in this ledger.',
    CONSTRAINT pk_ledger PRIMARY KEY(`ledger_id`)
) COMMENT 'Master reference table for ledger. Referenced by ledger_id.';

